function bindFilePopoverActions(container) {
  container.querySelectorAll('[data-copy-popover-path]').forEach(button => {
    button.addEventListener('click', event => {
      event.preventDefault();
      event.stopPropagation();
      copyFilePath(button.dataset.copyPopoverPath || '', 'full');
    });
  });
}

function clearTimer(timer) {
  if (timer) clearTimeout(timer);
  return null;
}

function numericOption(value, fallback) {
  const resolved = typeof value === 'function' ? value() : value;
  const number = Number(resolved);
  return Number.isFinite(number) ? number : fallback;
}

function viewportBounds(edgeGap = popoverEdgeGapPx()) {
  const width = Math.max(0, window.innerWidth || document.documentElement?.clientWidth || 0);
  const height = Math.max(0, window.innerHeight || document.documentElement?.clientHeight || 0);
  return {
    left: edgeGap,
    top: edgeGap,
    right: Math.max(edgeGap, width - edgeGap),
    bottom: Math.max(edgeGap, height - edgeGap),
  };
}

function clampToViewport(left, top, width, height, options = {}) {
  const bounds = viewportBounds(options.edgeGap ?? popoverEdgeGapPx());
  const minTop = Math.max(bounds.top, Number(options.minTop || 0));
  const maxLeft = Math.max(bounds.left, bounds.right - Math.max(0, width || 0));
  const maxTop = Math.max(minTop, bounds.bottom - Math.max(0, height || 0));
  return {
    left: Math.min(Math.max(bounds.left, left), maxLeft),
    top: Math.min(Math.max(minTop, top), maxTop),
  };
}

function stopPopoverEvent(event) {
  event.stopPropagation();
}

function closeOtherSessionPopovers(current, options = {}) {
  const force = options.force === true;
  for (const other of document.querySelectorAll('.pane-tab.popover-open, .panel-popover-zone.popover-open')) {
    if (other !== current) {
      const popover = other.querySelector?.(':scope > .session-popover, :scope > .panel-detail-popover');
      if (current === null && !force && popoverStillActive(other, popover)) continue;
      other.classList.remove('popover-open');
      delete other.dataset.popoverHoverState;
    }
  }
}

function popoverLifecycleActive(anchor, popover) {
  const state = anchor?.dataset?.popoverHoverState || '';
  return Boolean(
    state === 'open'
      || state === 'pending'
      || state === 'closing'
      || anchor?.classList?.contains?.('popover-open')
      || anchor?.matches?.(':hover')
      || popover?.matches?.(':hover')
  );
}

function popoverStillActive(anchor, popover) {
  const focused = document.activeElement;
  return Boolean(
    anchor?.matches?.(':hover')
      || popover?.matches?.(':hover')
      || (focused && (anchor.contains(focused) || popover?.contains(focused)))
  );
}

function bindPopoverHover(anchor, popover, handlers) {
  const queueOpen = handlers.queueOpen || handlers.keepOpen;
  const keepOpen = handlers.keepOpen || queueOpen;
  const closeSoon = handlers.closeSoon;
  const closeIfOutside = event => {
    const next = event?.relatedTarget;
    if (next && (anchor.contains(next) || popover?.contains(next))) return;
    closeSoon(event);
  };

  anchor.addEventListener('pointerenter', queueOpen);
  anchor.addEventListener('pointerleave', closeIfOutside);
  anchor.addEventListener('focusin', queueOpen);
  anchor.addEventListener('focusout', closeIfOutside);
  if (!popover) return;
  popover.addEventListener('pointerenter', keepOpen);
  popover.addEventListener('pointerleave', closeIfOutside);
  popover.addEventListener('click', stopPopoverEvent);
  popover.addEventListener('dragstart', stopPopoverEvent);
  popover.querySelectorAll('a').forEach(link => {
    link.addEventListener('pointerenter', keepOpen);
    link.addEventListener('click', stopPopoverEvent);
  });
}

function createHoverPopover(options) {
  const anchor = options.anchor;
  if (!anchor) return null;
  const stateClass = options.stateClass === undefined ? 'popover-open' : options.stateClass;
  let showTimer = null;
  let hideTimer = null;
  const popover = () => (typeof options.popover === 'function' ? options.popover() : options.popover);
  const canOpen = event => (typeof options.canOpen === 'function' ? options.canOpen(event) !== false : true);
  const stillActive = event => (typeof options.stillActive === 'function'
    ? options.stillActive(event) !== false
    : popoverStillActive(anchor, popover()));
  const markState = state => {
    if (!anchor.dataset) return;
    if (state) anchor.dataset.popoverHoverState = state;
    else delete anchor.dataset.popoverHoverState;
  };
  const cancelTimers = () => {
    showTimer = clearTimer(showTimer);
    hideTimer = clearTimer(hideTimer);
  };
  const closeNow = event => {
    cancelTimers();
    if (stateClass) anchor.classList.remove(stateClass);
    markState('');
    options.onClose?.(event);
  };
  const openNow = event => {
    cancelTimers();
    markState('');
    if (anchor.isConnected === false || !canOpen(event)) return;
    if (event && !stillActive(event)) return;
    if (stateClass && anchor.classList.contains(stateClass) && stillActive(event)) {
      markState('open');
      return;
    }
    options.position?.(event);
    options.closeOthers?.();
    options.onOpen?.(event);
    if (stateClass) anchor.classList.add(stateClass);
    markState('open');
    const activePopover = popover();
    if (activePopover && activePopover.dataset.hoverPopoverBound !== 'true') {
      bindPopoverHover(anchor, activePopover, {queueOpen, keepOpen: openNow, closeSoon});
      activePopover.dataset.hoverPopoverBound = 'true';
    }
  };
  function queueOpen(event) {
    hideTimer = clearTimer(hideTimer);
    markState('pending');
    if (anchor.isConnected === false || !canOpen(event)) {
      markState('');
      return;
    }
    if (stateClass && anchor.classList.contains(stateClass)) return;
    showTimer = clearTimer(showTimer);
    options.onQueue?.(event);
    const delay = numericOption(options.showDelay, popoverShowDelayMs);
    showTimer = setTimeout(() => openNow(event), Math.max(0, delay));
  }
  function closeSoon(event) {
    showTimer = clearTimer(showTimer);
    hideTimer = clearTimer(hideTimer);
    markState('closing');
    const delay = numericOption(options.hideDelay, popoverHideDelayMs);
    hideTimer = setTimeout(() => {
      if (anchor.isConnected === false) {
        markState('');
        hideTimer = null;
        if (stateClass) anchor.classList.remove(stateClass);
        options.onClose?.(event);
        return;
      }
      if (stillActive(event)) {
        markState('open');
        hideTimer = null;
        return;
      }
      if (stateClass) anchor.classList.remove(stateClass);
      markState('');
      hideTimer = null;
      options.onClose?.(event);
    }, Math.max(0, delay));
  }
  const initialPopover = popover();
  bindPopoverHover(anchor, initialPopover, {queueOpen, keepOpen: openNow, closeSoon});
  if (initialPopover) initialPopover.dataset.hoverPopoverBound = 'true';
  return {queueOpen, openNow, closeSoon, closeNow, cancelTimers};
}

function cssEscape(value) {
  if (window.CSS?.escape) return CSS.escape(value);
  return String(value).replace(/["\\]/g, '\\$&');
}

// Tab buttons are also drag handles, so activation waits until pointer release proves it was a click.
function bindTabActivation(node, activate, options = {}) {
  let pointerCandidate = false;
  let pointerActivated = false;
  let dragged = false;
  let startX = 0;
  let startY = 0;
  const stop = event => {
    if (options.stopPropagation) event.stopPropagation();
  };
  const ignored = event => options.ignore?.(event) === true;
  const resetPointer = () => {
    pointerCandidate = false;
    dragged = false;
  };

  node.addEventListener('pointerdown', event => {
    if (event.button !== 0 || ignored(event)) return;
    pointerCandidate = true;
    pointerActivated = false;
    dragged = false;
    startX = event.clientX;
    startY = event.clientY;
  });
  node.addEventListener('pointerup', event => {
    if (!pointerCandidate || event.button !== 0 || ignored(event)) {
      resetPointer();
      return;
    }
    const moved = Math.abs(event.clientX - startX) > 4 || Math.abs(event.clientY - startY) > 4;
    const wasDragged = dragged;
    resetPointer();
    if (wasDragged || moved) return;
    event.preventDefault();
    stop(event);
    pointerActivated = true;
    activate(event);
  });
  node.addEventListener('click', event => {
    if (ignored(event)) return;
    if (pointerActivated) {
      pointerActivated = false;
      event.preventDefault();
      stop(event);
      return;
    }
    event.preventDefault();
    stop(event);
    activate(event);
  });
  node.addEventListener('dragstart', () => {
    dragged = true;
    pointerCandidate = false;
    pointerActivated = false;
  });
  node.addEventListener('dragend', resetPointer);
}

// Tabs, headers, and popovers all use these helpers so badge precedence stays consistent.
function metaJoin(parts) {
  return parts.filter(Boolean).join('<span class="meta-sep"> · </span>');
}

function sessionNumberNameHtml(session) {
  const label = sessionLabel(session);
  const name = String(session);
  const nameHtml = name && name !== label ? `<span class="session-button-name">${esc(name)}</span>` : '';
  return `<span class="session-button-number">${esc(label)}</span>${nameHtml}`;
}

function yoloMarkerHtml(session, auto, options = {}) {
  const payload = options.payload || autoApproveStates.get(session);
  const locked = !auto && (options.locked === true || (options.locked !== false && autoApproveEnabledElsewhere(payload)));
  if (!auto && !locked && options.enabledOnly !== false) return '';
  const classes = ['session-yolo-marker'];
  if (auto) classes.push('active');
  else if (locked) classes.push('locked');
  else classes.push('inactive');
  if (options.yoloWorking) classes.push('working');
  if (readOnlyMode) classes.push('readonly');
  const yoloAttr = ` data-yolo-session="${esc(session)}"`;
  const toggleAttr = options.toggle && !readOnlyMode ? ` data-auto-session="${esc(session)}"` : '';
  const rotationStyle = options.yoloWorking ? ` style="--yolo-rotate-delay: ${esc(yoloRotationDelay())}"` : '';
  const stateText = auto ? 'on here' : (locked ? 'on elsewhere' : 'off');
  const title = options.toggle && readOnlyMode
    ? `YOLO ${stateText} for ${sessionLabel(session)}; readonly access`
    : (options.toggle ? `YOLO ${stateText} for ${sessionLabel(session)}` : `YOLO ${stateText}`);
  return `<span class="${esc(classes.join(' '))}"${yoloAttr}${toggleAttr}${rotationStyle} title="${esc(title)}">${esc(t('brand.marker'))}</span>`;
}

function pullRequestCompactBadgesHtml(session, pr) {
  const numberHtml = pullRequestNumberIndicatorHtml(session, pr);
  const statusHtml = pullRequestStatusIndicatorHtml(session, pr);
  const ciHtml = pullRequestCiIndicatorHtml(session, pr);
  const reviewHtml = pullRequestApprovalIndicatorHtml(session, pr);
  return [numberHtml, statusHtml, ciHtml, reviewHtml].filter(Boolean).join('');
}

function applySessionStateClasses(node, state) {
  node.classList.toggle('needs-attention', state?.attention === true);
  node.classList.toggle('needs-input', state?.key === 'needs-input');
  node.classList.toggle('needs-exec', state?.key === 'needs-approval');
  node.classList.toggle('needs-blocked', state?.key === 'blocked');
  syncAttentionAnimation(node, state?.attention === true);
}

function panelHeaderStateHtml(state) {
  return state ? sessionStateHtml(state) : '';
}

function currentBranchSubject(git) {
  const branches = git?.other_branches?.branches || [];
  const current = branches.find(branch => branch.current);
  return current?.subject || '';
}

function isDefaultBranch(git) {
  return ['main', 'master'].includes(String(git?.branch || ''));
}

function gitHeadSubject(git) {
  return String(git?.head || '').replace(/^[0-9a-f]{7,40}\s+/, '');
}

function pullRequestNumberFromSubject(subject) {
  const match = String(subject || '').match(/\(#(\d+)\)\s*$/);
  return match ? Number(match[1]) : null;
}

function subjectWithoutPullRequestNumber(subject) {
  return String(subject || '').replace(/\s*\(#\d+\)\s*$/, '').trim();
}

function githubPullRequestUrlFromGit(git, number) {
  const repoUrl = git?.github_repo?.url;
  return repoUrl && number ? `${repoUrl}/pull/${number}` : '';
}

function defaultBranchHeadPullRequest(info) {
  const project = info?.project || {};
  const git = project.git;
  if (!isDefaultBranch(git)) return null;
  const subject = gitHeadSubject(git);
  const number = pullRequestNumberFromSubject(subject);
  if (!number) return null;
  const existing = project.pull_request?.number === number ? project.pull_request : {};
  const title = subjectWithoutPullRequestNumber(existing.title || subject);
  const description = subjectWithoutPullRequestNumber(existing.description || subject);
  return {
    ...existing,
    number,
    title,
    description,
    url: existing.url || githubPullRequestUrlFromGit(git, number),
    checks: existing.checks || {state: 'unknown'},
    // A (#NNNN) in the default branch's HEAD merge commit means that PR is, by definition, merged
    // (it is in main's history) — so label it MERGED even though we only inferred it from the subject.
    status_label: existing.status_label || 'merged',
    source_only: true,
  };
}

function displayPullRequest(info) {
  return defaultBranchHeadPullRequest(info) || info?.project?.pull_request || null;
}

function metadataBadgeKey(session, badge) {
  return `${session}:${badge}`;
}

function metadataBadgePulseClass(session, badge) {
  if (!session) return '';
  const until = metadataBadgePulseUntil.get(metadataBadgeKey(session, badge));
  if (!until || until <= Date.now()) return '';
  return ' metadata-pulse';
}

function metadataBadgeClasses(session, badge, classes) {
  return `${classes}${metadataBadgePulseClass(session, badge)}`;
}

function updateMetadataBadgePulses(meta) {
  const now = Date.now();
  for (const [key, until] of metadataBadgePulseUntil.entries()) {
    if (until <= now) metadataBadgePulseUntil.delete(key);
  }
  for (const [session, info] of Object.entries(meta?.sessions || {})) {
    const pulses = info?.metadata_badge_pulse_remaining_ms || {};
    for (const badge of ['main', 'pr', 'status', 'ci']) {
      const remaining = Number(pulses[badge] || 0);
      if (remaining > 0) {
        metadataBadgePulseUntil.set(metadataBadgeKey(session, badge), now + remaining);
      }
    }
  }
}

function defaultBranchBadgeHtml(session, info) {
  if (!isDefaultBranch(info?.project?.git)) return '';
  return `<span class="${metadataBadgeClasses(session, 'main', 'ci-indicator tab-symbol branch-indicator')}">MAIN</span>`;
}

function sessionWorkDescription(session, info, limit = 96) {
  const project = info?.project || {};
  const git = project.git;
  const pr = displayPullRequest(info);
  if (pr?.number) {
    const status = pullRequestStatusLabel(pr);
    const title = pr.title || pr.description || '';
    const prefix = `#${pr.number}${status && status !== 'unknown' ? ` ${status}` : ''}`;
    return shortText(title ? `${prefix}: ${title}` : prefix, limit);
  }
  const linear = project.linear || [];
  const issue = linear.find(item => item.title);
  if (issue) return shortText(`${issue.identifier}: ${issue.title}`, limit);
  const subject = currentBranchSubject(git);
  if (subject) return shortText(subject, limit);
  if (git?.branch) return shortText(shortBranch(git.branch), limit);
  return shortText(projectDirName(session, info), limit);
}

function sessionTabDescription(session, info) {
  const pr = displayPullRequest(info);
  if (pr?.number) {
    const title = pr.title || pr.description || '';
    if (title) return shortText(title, 72);
  }
  return sessionWorkDescription(session, info, 72);
}

function tabMenuDetailText(item, info = transcriptMeta.sessions?.[item]) {
  if (isInfoItem(item)) return 'all branches sorted by recent activity';
  const project = info?.project || {};
  const git = project.git;
  const parts = [];
  if (git?.branch) parts.push(git.branch);
  const path = panelFullPath(item, info);
  if (path) parts.push(compactHomePath(path));
  const pr = displayPullRequest(info);
  const linear = (project.linear || []).map(issue => issue.identifier).filter(Boolean).join(', ');
  if (linear) parts.push(linear);
  if (pr?.number) {
    const status = pullRequestStatusLabel(pr);
    parts.push(`#${pr.number}${status && status !== 'unknown' ? ` ${status}` : ''}`);
  }
  const desc = sessionWorkDescription(item, info, 180);
  if (desc && !parts.includes(desc)) parts.push(desc);
  return parts.join(' · ') || itemLabel(item);
}

function projectDirName(session, info) {
  if (!info) return t('common.loading');
  const project = info?.project || {};
  const git = project.git;
  const path = git?.root || git?.cwd || info?.selected_pane?.current_path || '';
  return pathBasename(path) || 'no path';
}

function pathBasename(path) {
  const text = String(path || '').replace(/\/+$/, '');
  if (!text) return '';
  const parts = text.split('/');
  return parts[parts.length - 1] || '';
}

function filePopoverHtml(item) {
  const path = fileItemPath(item);
  const state = openFiles.get(path) || {};
  const rows = filePopoverRows(path, state);
  return `<div class="session-popover file-popover" role="tooltip">
    <div class="popover-head">
      <div>
        <div class="popover-title">${esc(basenameOf(path))}</div>
      </div>
    </div>
    ${rows.join('')}
  </div>`;
}

function filePopoverRows(path, state = {}) {
  const kind = state.kind === 'image' ? t('popover.kind.image') : state.kind === 'text' ? t('popover.kind.text') : state.kind || t('popover.kind.file');
  const status = state.dirty ? t('filetab.modified') : state.loading ? t('common.loading') : state.error ? String(state.error) : kind;
  const rows = [
    popoverRow(t('popover.path'), filePopoverPathHtml(path)),
  ];
  if (status && status !== kind) rows.push(popoverPairRow(t('popover.type'), esc(kind), t('popover.status'), esc(status)));
  else rows.push(popoverRow(t('popover.type'), esc(kind)));
  if (Number.isFinite(state.size)) rows.push(popoverRow(t('popover.size'), formatFileSize(state.size)));
  return rows;
}

function pathCopyButtonHtml(path, options = {}) {
  const className = ['path-copy-button', options.className || ''].filter(Boolean).join(' ');
  const dataAttr = options.dataAttr || 'data-copy-path';
  const title = options.title || 'Copy path';
  return `<button type="button" class="${esc(className)}" ${dataAttr}="${esc(path)}" title="${esc(title)}" aria-label="${esc(options.ariaLabel || title)}"></button>`;
}

function filePopoverPathHtml(path) {
  return `<span class="popover-copy-value">${esc(path)}</span>${pathCopyButtonHtml(path, {className: 'popover-copy-button', dataAttr: 'data-copy-popover-path'})}`;
}

function sessionPopoverHtml(session, info, agentKind, autoEnabled, state = sessionState(session, info)) {
  const project = info?.project || {};
  const git = project.git;
  const pr = displayPullRequest(info);
  const linear = project.linear || [];
  const pane = info?.selected_pane;
  const description = sessionWorkDescription(session, info, 220);
  const title = `${sessionLabel(session)} · ${projectDirName(session, info)}`;
  const subtitle = description || git?.branch || pane?.current_path || 'no checkout detected';
  const rows = [];
  const stateValue = `${sessionStateHtml(state)} <span class="meta-muted">${esc(state.reason)}</span>`;
  const autoPayload = autoApproveStates.get(session);
  const autoElsewhere = autoApproveEnabledElsewhere(autoPayload);
  const autoText = autoEnabled ? 'YOLO on' : (autoElsewhere ? 'YOLO elsewhere' : '');
  const agentValue = agentKind ? `${agentName(agentKind)}${autoText ? ` · ${autoText}` : ''}` : (autoText || 'not detected');
  const displayPath = panelFullPath(session, info) || pane?.current_path || 'not available';
  rows.push(popoverPairRow(t('popover.state'), stateValue, t('popover.agent'), agentValue));
  const activity = sessionActivitySummary(session);
  if (activity?.local) rows.push(popoverRow(yoagentTabLabel(), esc(activity.local)));
  rows.push(popoverRow(t('popover.path'), displayPath));
  if (git?.branch) rows.push(popoverRow(t('popover.branch'), `${branchLinkHtml(git, git.branch)}${git.upstream ? `<span class="meta-muted"> -> ${esc(git.upstream)}</span>` : ''}`));
  if (Number.isFinite(git?.dirty_count) || Number.isFinite(git?.ahead) || Number.isFinite(git?.behind)) {
    rows.push(popoverRow(t('popover.git'), gitStatusText(git)));
  }
  let linearValue = '';
  let linearDesc = '';
  if (linear.length) {
    linearValue = linearInlineHtml(linear);
    linearDesc = linearDescriptionsInlineHtml(linear);
    if (linearValue) rows.push(popoverRow('Linear', linearValue));
    if (linearDesc) rows.push(popoverRow(t('popover.details'), linearDesc));
  }
  let prDesc = '';
  if (pr?.number) {
    const prParts = [pullRequestLinkHtml(pr), pullRequestAuthorHtml(pr)].filter(Boolean);
    const checks = pullRequestChecksHtml(pr);
    if (checks) prParts.push(checks);
    const review = pullRequestReviewInlineHtml(pr);
    if (review) prParts.push(review);
    rows.push(popoverRow('PR', metaJoin(prParts)));
    prDesc = pullRequestDescriptionInlineHtml(pr);
  }
  if (prDesc) {
    rows.push(popoverRow(t('popover.desc'), prDesc));
  }
  const subject = currentBranchSubject(git);
  if (subject && !pr?.number) rows.push(popoverRow(t('popover.desc'), `<div class="popover-desc">${esc(subject)}</div>`));
  if (git?.root && git.root !== displayPath) rows.push(popoverRow(t('popover.repo'), git.root));
  if (git?.head) rows.push(popoverRow('HEAD', git.head));
  return `<div class="session-popover" role="tooltip">
    <div class="popover-head">
      <div>
        <div class="popover-title">${esc(title)}</div>
        <div class="popover-subtitle">${esc(subtitle)}</div>
      </div>
    </div>
    ${rows.join('')}
    ${otherBranchesHtml(git)}
  </div>`;
}

function popoverRow(label, valueHtml) {
  return `<div class="popover-row"><div class="popover-label">${esc(label)}</div><div class="popover-value">${stripTitleAttrs(valueHtml)}</div></div>`;
}

function popoverPairRow(leftLabel, leftValueHtml, rightLabel, rightValueHtml) {
  return `<div class="popover-row compact">
    <div class="popover-label">${esc(leftLabel)}</div><div class="popover-value">${stripTitleAttrs(leftValueHtml)}</div>
    <div class="popover-label">${esc(rightLabel)}</div><div class="popover-value">${stripTitleAttrs(rightValueHtml)}</div>
  </div>`;
}

function stripTitleAttrs(html) {
  return String(html || '').replace(/\s+title="[^"]*"/g, '');
}

function pullRequestDescriptionInlineHtml(pr) {
  const title = String(pr?.title || '').trim();
  const description = String(pr?.description || '').trim();
  const body = description && description !== title ? description.replace(/^#+\s*Overview:\s*/i, '').trim() : '';
  const text = [title, body].filter(Boolean).join(' · ');
  return text ? esc(shortText(text, 180)) : '';
}

function linearInlineHtml(issues) {
  const parts = [];
  for (const issue of issues || []) {
    const label = issue.identifier || '';
    if (!label) continue;
    const link = linkHtml(issue.url, label, issue.title || '');
    if (!link) continue;
    const state = issue.state ? `<span class="meta-muted"> ${esc(issue.state)}</span>` : '';
    parts.push(`${link}${state}`);
  }
  return metaJoin(parts);
}

function linearDescriptionsInlineHtml(issues) {
  const parts = [];
  for (const issue of issues || []) {
    if (!issue?.title) continue;
    const prefix = issue.identifier ? `${issue.identifier} ` : '';
    parts.push(`${prefix}${issue.title}`);
  }
  return parts.length ? esc(shortText(parts.join(' · '), 180)) : '';
}

function gitStatusText(git) {
  const parts = [];
  if (Number.isFinite(git.dirty_count)) parts.push(`${git.dirty_count} dirty`);
  if (Number.isFinite(git.ahead) && git.ahead > 0) parts.push(`${git.ahead} ahead`);
  if (Number.isFinite(git.behind) && git.behind > 0) parts.push(`${git.behind} behind`);
  return esc(parts.length ? parts.join(' · ') : 'clean');
}

function branchLinkHtml(git, branchName) {
  return esc(branchName || '');
}

function linearIssueHtml(issue) {
  const label = `${issue.identifier}${issue.state ? ` ${issue.state}` : ''}`;
  return linkHtml(issue.url, label, issue.title || '');
}

function linearIssueLinkHtml(identifier) {
  if (!identifier) return '';
  return linkHtml(`https://linear.app/nv/issue/${encodeURIComponent(identifier)}`, identifier, identifier);
}

function pullRequestLinkForBranch(git, branch) {
  const pr = branch?.pull_request;
  const repoUrl = git?.github_repo?.url;
  if (!pr?.number) return '';
  const url = pr.url || (repoUrl ? `${repoUrl}/pull/${pr.number}` : '');
  const status = pullRequestStatusDisplay(pr);
  const label = `#${pr.number}${status && status !== 'unknown' ? ` ${status}` : ''}`;
  return linkHtml(url, label, pr.title || pr.description || branch.subject || '', pullRequestStatusClass(pr));
}

function pullRequestTextForBranch(pr, fallback = '') {
  if (!pr?.number) return '';
  const status = pullRequestStatusDisplay(pr);
  return [`#${pr.number}${status && status !== 'unknown' ? ` ${status}` : ''}`, pr.title || pr.description || fallback].filter(Boolean).join(' ');
}

function otherBranchesHtml(git) {
  const inventory = git?.other_branches || {};
  const branches = inventory.branches || [];
  if (!branches.length) {
    return `<div class="branch-list"><div class="branch-list-title">${esc(t('branch.all'))}</div><div class="meta-muted">${esc(t('branch.none'))}</div></div>`;
  }
  const items = branches.map(branch => {
    const branchLink = branchLinkHtml(git, branch.name);
    const prLink = pullRequestLinkForBranch(git, branch);
    const linearLinks = (branch.linear_ids || []).map(linearIssueLinkHtml).filter(Boolean).join(' ');
    const meta = [prLink, linearLinks, esc(branch.updated || '')].filter(Boolean).join(' ');
    return `<div class="branch-item">
      <div class="branch-name">${branch.current ? `<span class="info-branch-current">${esc(t('branch.current'))}</span> ` : ''}${branchLink}</div>
      <div class="branch-meta">${meta}</div>
      <div class="branch-subject">${esc(shortText(branch.subject || '', 240))}</div>
    </div>`;
  }).join('');
  const hidden = Number(inventory.hidden_count || 0) > 0
    ? `<div class="meta-muted">${esc(t('branch.more', {count: inventory.hidden_count}))}</div>`
    : '';
  return `<div class="branch-list"><div class="branch-list-title">${esc(t('branch.all'))}</div>${items}${hidden}</div>`;
}

function dragPayload(event) {
  const raw = event.dataTransfer?.getData('application/x-yolomux-session') || '';
  if (!raw && dragSession) return {session: dragSession, sourceSlot: dragSourceSlot};
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw);
    return isLayoutItem(parsed.session) ? parsed : null;
  } catch (_) {
    return isLayoutItem(raw) ? {session: raw, sourceSlot: null} : null;
  }
}

function normalizeFileDragPayload(parsed) {
  if (!parsed?.path && !Array.isArray(parsed?.paths)) return null;
  const paths = Array.isArray(parsed.paths) ? parsed.paths.filter(Boolean) : [parsed.path].filter(Boolean);
  return paths.length ? {...parsed, path: parsed.path || paths[0], paths} : null;
}

function parseFileDragPayload(raw) {
  if (!raw) return null;
  try {
    return normalizeFileDragPayload(JSON.parse(raw));
  } catch (_) {
    return null;
  }
}

function hasYolomuxFileDrag(event) {
  return Array.from(event.dataTransfer?.types || []).includes('application/x-yolomux-file');
}

function fileDragPayload(event) {
  const raw = event.dataTransfer?.getData('application/x-yolomux-file') || '';
  return parseFileDragPayload(raw) || (hasYolomuxFileDrag(event) ? dragFilePayloadState : null);
}

async function openDraggedFilesInEditor(payload, options = {}) {
  const paths = Array.from(new Set((payload?.paths || [payload?.path]).filter(Boolean)));
  if (!paths.length) return;
  let opened = 0;
  for (const [index, path] of paths.entries()) {
    try {
      const info = await fetchFilePathInfo(path);
      if (info.kind !== 'file') continue;
      await openFileInEditor(path, info, {
        forceNewTab: true,
        targetSlot: options.targetSlot || null,
        targetZone: options.targetZone || 'middle',
        targetIndex: options.targetIndex == null ? null : Number(options.targetIndex) + index,
      });
      // Unify with double-click: a dragged CHANGED (tracked, has-diff) file opens in the SAME diff
      // view (ensureCodeMirrorDiffPanel) as openChangedFileInDiff, not a plain edit-mode editor.
      // Unchanged/untracked files have no diff available and stay in edit.
      await refreshOpenFileDiff(path, {silent: true});
      const draggedState = openFiles.get(path);
      if (draggedState && openFileDiffAvailable(draggedState)) {
        setFileEditorViewMode(path, 'diff', fileEditorItemFor(path));
        for (const draggedPanel of fileEditorPanelsForPath(path)) {
          renderFileEditorPanel(draggedPanel, draggedPanel.dataset.layoutItem || fileEditorItemFor(path));
        }
      }
      // #260: a drag-drop open is a FRESH open at the current disk state, not a "changed on disk"
      // conflict. If the just-opened file is NOT dirty, clear any external-change flags so it never
      // pops a spurious reload prompt (this matches double-click's openChangedFileInDiff, which opens
      // with a clean baseline). A dirty file keeps its conflict state so real unsaved-edit warnings stay.
      if (draggedState && !draggedState.dirty) {
        delete draggedState.externalChanged;
        delete draggedState.externalMissing;
        delete draggedState.externalError;
        delete draggedState.externalChangeEditPrompted;
        renderOpenFilePath(path);
      }
      opened += 1;
    } catch (error) {
      showFileOpenError(path, error);
    }
  }
  if (opened) statusOk(`opened ${esc(opened === 1 ? basenameOf(paths[0]) : `${opened} files`)}`);
}

function terminalCurrentPath(session) {
  const info = transcriptMeta.sessions?.[session];
  return terminalDisplayPane(info)?.current_path || info?.selected_pane?.current_path || '';
}

function pathRelativeToDirectory(path, directory) {
  const fullPath = String(path || '');
  const rawBase = String(directory || '');
  const base = rawBase === '/' ? '/' : rawBase.replace(/\/+$/, '');
  if (!fullPath || !base || !fullPath.startsWith('/')) return fullPath;
  if (fullPath === base) return '.';
  if (base === '/') return fullPath.slice(1);
  if (!fullPath.startsWith(`${base}/`)) return fullPath;
  return fullPath.slice(base.length + 1);
}

function terminalFileReference(session, path) {
  return pathRelativeToDirectory(path, terminalCurrentPath(session));
}

function terminalFileReferences(session, payload) {
  const paths = Array.isArray(payload?.paths) ? payload.paths : [payload?.path].filter(Boolean);
  return paths.map(path => terminalFileReference(session, path));
}

function transparentNativeDragImage() {
  if (transparentDragImage) return transparentDragImage;
  const node = document.createElement('div');
  node.className = 'transparent-drag-image';
  node.style.position = 'fixed';
  node.style.left = '-10000px';
  node.style.top = '-10000px';
  node.style.width = '1px';
  node.style.height = '1px';
  node.style.opacity = '0';
  node.style.pointerEvents = 'none';
  document.body.appendChild(node);
  transparentDragImage = node;
  return node;
}

function moveCustomDragPreview(event) {
  if (!customDragPreview || !Number.isFinite(event.clientX) || !Number.isFinite(event.clientY)) return;
  customDragPreview.style.left = `${Math.round(event.clientX - customDragPreviewOffset.x)}px`;
  customDragPreview.style.top = `${Math.round(event.clientY - customDragPreviewOffset.y)}px`;
}

function bindCustomDragPreviewListeners() {
  document.addEventListener?.('dragover', moveCustomDragPreview, true);
  document.addEventListener?.('drag', moveCustomDragPreview, true);
  document.addEventListener?.('drop', stopCustomDragPreview, true);
  document.addEventListener?.('dragend', stopCustomDragPreview, true);
}

function unbindCustomDragPreviewListeners() {
  document.removeEventListener?.('dragover', moveCustomDragPreview, true);
  document.removeEventListener?.('drag', moveCustomDragPreview, true);
  document.removeEventListener?.('drop', stopCustomDragPreview, true);
  document.removeEventListener?.('dragend', stopCustomDragPreview, true);
}

function stopCustomDragPreview() {
  unbindCustomDragPreviewListeners();
  customDragPreview?.remove();
  customDragPreview = null;
  closeFileImagePreview();
}

// #47: tab drags use the native drag image (see startSessionDrag) — the clone-follow tab preview is
// gone. The custom-preview machinery below is retained only for the rich FILE drag preview.
function startFileDragPreview(event, paths, entry) {
  stopCustomDragPreview();
  const normalizedPaths = Array.from(new Set((paths || []).filter(Boolean)));
  const firstPath = normalizedPaths[0] || '';
  const preview = document.createElement('div');
  preview.className = 'file-drag-image drag-image';
  const title = normalizedPaths.length === 1 ? basenameOf(firstPath) : `${normalizedPaths.length} items`;
  const pathRows = normalizedPaths.slice(0, 4)
    .map(path => `<div class="file-drag-path">${esc(path)}</div>`)
    .join('');
  const more = normalizedPaths.length > 4 ? `<div class="file-drag-more">+ ${normalizedPaths.length - 4} more</div>` : '';
  preview.innerHTML = `
    <div class="file-drag-main">
      ${fileDragPreviewMedia(firstPath, entry)}
      <div class="file-drag-copy">
        <div class="file-drag-title">${esc(title)}</div>
        ${pathRows}${more}
      </div>
    </div>`;
  preview.style.position = 'fixed';
  preview.style.pointerEvents = 'none';
  preview.style.zIndex = '99999';
  document.body.appendChild(preview);
  customDragPreview = preview;
  customDragPreviewOffset = {x: -14, y: -14};
  moveCustomDragPreview(event);
  bindCustomDragPreviewListeners();
  preview.getBoundingClientRect();
  event.dataTransfer?.setDragImage?.(transparentNativeDragImage(), 0, 0);
}

function fileDragPreviewMedia(path, entry) {
  const kind = entry?.kind || 'file';
  if (kind === 'file' && IMAGE_EXTENSIONS.has(fileExtensionOf(path))) {
    return `<img class="file-drag-thumb" src="${rawFileUrl(path)}" alt="">`;
  }
  const icon = kind === 'dir' ? '▸' : '📄';
  return `<span class="file-drag-thumb file-drag-icon" aria-hidden="true">${icon}</span>`;
}

function startSessionDrag(event, session, sourceSlot = null) {
  dragSession = session;
  dragSourceSlot = sourceSlot;
  const payload = JSON.stringify({session, sourceSlot});
  event.dataTransfer.effectAllowed = 'move';
  event.dataTransfer.setData('application/x-yolomux-session', payload);
  event.dataTransfer.setData('text/plain', session);
  // #47: use the NATIVE drag image — a one-time compositor snapshot of the tab itself — instead of the
  // JS clone-follow preview. That removes the per-move reposition, the two document capture listeners,
  // and the animated heavyweight clone that caused the "won't budge" first drag and the per-move jank.
  const source = event.currentTarget;
  const rect = source?.getBoundingClientRect?.();
  if (rect && event.dataTransfer?.setDragImage) {
    const offsetX = Math.max(0, Math.min(rect.width || 0, (event.clientX || 0) - rect.left));
    const offsetY = Math.max(0, Math.min(rect.height || 0, (event.clientY || 0) - rect.top));
    event.dataTransfer.setDragImage(source, offsetX, offsetY);
  }
  resetDragTabRectCache();
}

function endSessionDrag(event) {
  dragSession = null;
  dragSourceSlot = null;
  resetDragTabRectCache();
  stopCustomDragPreview();
  sessionButtons.classList.remove('drag-over');
  clearDropPreview();
  // DOIT.6 #30: flush any tab/preferences re-renders that were deferred during the drag.
  if (pendingTabStripRender) { pendingTabStripRender = false; renderPaneTabStrips(); }
  if (pendingPreferencesRender) { pendingPreferencesRender = false; renderPreferencesPanels(); }
  // DOIT.6 #114: flush the full panel re-render deferred during the drag (dragSession is null now).
  if (pendingPanelsRender) { pendingPanelsRender = false; renderPanels(); }
}
function layoutWithoutItemFromSlots(item, slots = layoutSlots, options = {}) {
  const next = emptyLayoutSlots();
  next[layoutTreeKey] = slots?.[layoutTreeKey] || null;
  const preserveEmptySlot = options.preserveEmptySlot || null;
  const preserveRemovedSlot = options.preserveRemovedSlot === true;
  const preservePlaceholders = options.preservePlaceholders !== false;
  for (const side of layoutSlotKeys(slots)) {
    if (paneIsPlaceholder(side, slots)) {
      if (preservePlaceholders) next[side] = emptyPlaceholderPaneState();
      continue;
    }
    const hadItem = paneTabs(side, slots).includes(item);
    const active = activeItemForSide(side, slots);
    const tabs = paneTabs(side, slots).filter(value => value !== item);
    next[side] = !tabs.length && (side === preserveEmptySlot || (preserveRemovedSlot && hadItem))
      ? emptyPlaceholderPaneState()
      : paneStateWithTabs(tabs, active === item ? null : active);
  }
  return next;
}

function layoutWithoutItem(item, options = {}) {
  return layoutWithoutItemFromSlots(item, layoutSlots, options);
}

function removeSessionFromLayout(item) {
  if (!itemInLayout(item)) return;
  const isFiles = isFileExplorerItem(item);
  applyLayoutSlots(layoutWithoutItem(item, {
    preserveRemovedSlot: !isFiles,
    preservePlaceholders: !isFiles,
  }), {
    message: `${itemLabel(item)} hidden from layout`,
  });
}

function removePaneFromLayout(item) {
  const slot = slotForSession(item);
  if (!slot) return;
  const moved = paneTabs(slot);
  applyLayoutSlots(layoutWithoutSlot(slot, {preserveRemovedSlot: shouldPreserveClosedPaneSlot(slot)}), {
    message: moved.length ? `${moved.map(itemLabel).join(', ')} hidden from layout` : '',
  });
}

function shouldPreserveClosedPaneSlot(slot) {
  if (!slot || isFileExplorerItem(activeItemForSide(slot))) return false;
  return layoutSlotKeys().some(side => side !== slot && isFileExplorerItem(activeItemForSide(side)));
}

function layoutWithoutSlot(slot, options = {}) {
  const next = emptyLayoutSlots();
  next[layoutTreeKey] = layoutSlots[layoutTreeKey];
  for (const side of layoutSlotKeys()) {
    if (side === slot) {
      if (options.preserveRemovedSlot === true) next[side] = emptyPlaceholderPaneState();
      continue;
    }
    next[side] = paneStateForLayoutSlot(side);
  }
  return next;
}

function appendUniqueItems(target, items) {
  for (const item of items) {
    if (isLayoutItem(item) && !target.includes(item)) target.push(item);
  }
  return target;
}

// Per-pane tab cap (LRU eviction). Records when a tab was last activated so the oldest UNUSED tab
// can auto-close once a pane grows past appearance.max_tabs_per_pane.
function recordTabActivation(item) {
  if (isLayoutItem(item)) tabLastActivatedAt.set(item, Date.now());
}

function maxTabsPerPane() {
  const raw = Math.floor(Number(initialSetting('appearance.max_tabs_per_pane', 10)));
  if (!Number.isFinite(raw)) return 10;
  return Math.max(2, Math.min(30, raw));
}

// A tab may be auto-evicted unless it is the one being kept active, the Finder dock, or a
// dirty/unsaved editor (never silently drop unsaved edits).
function tabIsEvictableForCap(item, keepItem) {
  if (item === keepItem || isFileExplorerItem(item)) return false;
  if (isFileEditorItem(item)) {
    const state = openFiles.get(fileItemPath(item));
    if (state && state.dirty) return false;
  }
  return true;
}

// Given a pane's tab list (newest tab already inserted) return the least-recently-used evictable
// tabs to drop so the pane fits the cap. Keeps keepItem, dirty editors, and the Finder.
function tabsToEvictForCap(tabs, keepItem) {
  const cap = maxTabsPerPane();
  const overflow = tabs.length - cap;
  if (overflow <= 0) return [];
  const evictable = tabs.filter(item => tabIsEvictableForCap(item, keepItem));
  if (!evictable.length) return [];
  const byLeastRecent = [...evictable].sort((a, b) => (tabLastActivatedAt.get(a) || 0) - (tabLastActivatedAt.get(b) || 0));
  return byLeastRecent.slice(0, Math.min(overflow, byLeastRecent.length));
}

function paneTabsWithoutFinder(slot, slots = layoutSlots) {
  return paneTabs(slot, slots).filter(item => !isFileExplorerItem(item));
}

function canPaneExpand(item, slots = layoutSlots) {
  const targetSlot = slotForItem(item, slots);
  if (!targetSlot || isFileExplorerItem(activeItemForSide(targetSlot, slots))) return false;
  if (!activeItemForSide(targetSlot, slots)) return false;
  return layoutSlotKeys(slots).some(slot => (
    slot !== targetSlot
    && !isFileExplorerItem(activeItemForSide(slot, slots))
    && paneTabsWithoutFinder(slot, slots).length > 0
  ));
}

function minimizePaneFromLayout(item) {
  const sourceSlot = slotForSession(item);
  if (!sourceSlot) return;
  if (isFileExplorerItem(activeItemForSide(sourceSlot))) {
    removePaneFromLayout(item);
    return;
  }
  const minimizedTabs = paneTabsWithoutFinder(sourceSlot);
  const targetSlot = largestNonFileExplorerPaneSlot(new Set([sourceSlot]));
  if (!targetSlot || !minimizedTabs.length) {
    removePaneFromLayout(item);
    return;
  }
  const targetActive = activeItemForSide(targetSlot);
  const next = layoutWithoutSlot(sourceSlot, {preserveRemovedSlot: shouldPreserveClosedPaneSlot(sourceSlot)});
  const targetTabs = appendUniqueItems(paneTabsWithoutFinder(targetSlot, next), minimizedTabs);
  next[targetSlot] = paneStateWithTabs(targetTabs, targetActive);
  applyLayoutSlots(next, {
    focusSession: targetActive || targetTabs[0],
    prune: false,
    message: `${minimizedTabs.map(itemLabel).join(', ')} minimized`,
  });
}

function finderLeadsExpandedPane(finderSlot, targetSlot) {
  const finderRect = layoutColumnNode(finderSlot)?.getBoundingClientRect();
  const targetRect = layoutColumnNode(targetSlot)?.getBoundingClientRect();
  if (finderRect && targetRect && Math.abs(finderRect.left - targetRect.left) > 1) return finderRect.left < targetRect.left;
  const leaves = layoutLeafSlots(layoutSlots[layoutTreeKey]);
  const finderIndex = leaves.indexOf(finderSlot);
  const targetIndex = leaves.indexOf(targetSlot);
  if (finderIndex !== -1 && targetIndex !== -1) return finderIndex < targetIndex;
  return true;
}

function expandPaneFromLayout(item) {
  const targetSlot = slotForSession(item);
  if (!targetSlot || !canPaneExpand(item)) return;
  const active = activeItemForSide(targetSlot);
  if (!active) return;
  const finderSlot = slotForSession(fileExplorerItemId);
  const targetTabs = appendUniqueItems([], paneTabsWithoutFinder(targetSlot));
  for (const slot of layoutSlotKeys()) {
    if (slot === targetSlot) continue;
    appendUniqueItems(targetTabs, paneTabsWithoutFinder(slot));
  }
  const next = emptyLayoutSlots();
  next[targetSlot] = paneStateWithTabs(targetTabs, active);
  if (finderSlot && finderSlot !== targetSlot) {
    next[finderSlot] = paneStateWithTabs([fileExplorerItemId], fileExplorerItemId);
    const finderFirst = finderLeadsExpandedPane(finderSlot, targetSlot);
    next[layoutTreeKey] = finderFirst
      ? splitNode('row', leafNode(finderSlot), leafNode(targetSlot), fileExplorerSplitPercent)
      : splitNode('row', leafNode(targetSlot), leafNode(finderSlot), 100 - fileExplorerSplitPercent);
  } else {
    next[layoutTreeKey] = leafNode(targetSlot);
  }
  applyLayoutSlots(next, {
    focusSession: active,
    prune: false,
    message: `${itemLabel(active)} expanded`,
  });
}

function visibleNonFinderPaneItems(slots = layoutSlots) {
  const result = [];
  for (const slot of layoutSlotKeys(slots)) appendUniqueItems(result, paneTabsWithoutFinder(slot, slots));
  return result;
}

function firstNonFinderPaneSlot(slots = layoutSlots) {
  return layoutSlotKeys(slots).find(slot => !isFileExplorerItem(activeItemForSide(slot, slots)) && paneTabsWithoutFinder(slot, slots).length > 0) || null;
}

function setLayoutToSinglePane() {
  const items = visibleNonFinderPaneItems();
  if (!items.length) return;
  const active = items.includes(focusedPanelItem) ? focusedPanelItem : items[0];
  const finderSlot = slotForSession(fileExplorerItemId);
  const targetSlot = firstNonFinderPaneSlot() || (finderSlot === 'left' ? 'right' : 'left');
  const next = emptyLayoutSlots();
  next[targetSlot] = paneStateWithTabs(items, active);
  if (finderSlot) {
    next[finderSlot] = paneStateWithTabs([fileExplorerItemId], fileExplorerItemId);
    const finderFirst = finderLeadsExpandedPane(finderSlot, targetSlot);
    next[layoutTreeKey] = finderFirst
      ? splitNode('row', leafNode(finderSlot), leafNode(targetSlot), fileExplorerSplitPercent)
      : splitNode('row', leafNode(targetSlot), leafNode(finderSlot), 100 - fileExplorerSplitPercent);
  } else {
    next[layoutTreeKey] = leafNode(targetSlot);
  }
  applyLayoutSlots(next, {focusSession: active, prune: false, message: 'single pane layout'});
}

function setLayoutToSplitPanes() {
  const items = visibleNonFinderPaneItems();
  if (!items.length) return;
  const finderSlot = slotForSession(fileExplorerItemId);
  const preferredSlots = basePaneKeys.filter(slot => slot !== finderSlot);
  while (preferredSlots.length < 2) preferredSlots.push(nextLayoutSlot({...layoutSlots, [preferredSlots[0] || 'left']: emptyPaneState()}));
  const leftSlot = preferredSlots[0] || 'left';
  const rightSlot = preferredSlots[1] || 'right';
  const groups = [[], []];
  const assigned = new Set();
  for (const item of items) {
    const slot = slotForSession(item);
    if (slot === leftSlot) {
      groups[0].push(item);
      assigned.add(item);
    } else if (slot === rightSlot) {
      groups[1].push(item);
      assigned.add(item);
    }
  }
  for (const item of items) {
    if (assigned.has(item)) continue;
    groups[groups[0].length <= groups[1].length ? 0 : 1].push(item);
  }
  if (!groups[1].length && groups[0].length > 1) groups[1].push(...groups[0].splice(Math.ceil(groups[0].length / 2)));
  const active = items.includes(focusedPanelItem) ? focusedPanelItem : items[0];
  const next = emptyLayoutSlots();
  next[leftSlot] = paneStateWithTabs(groups[0], groups[0].includes(active) ? active : groups[0][0]);
  if (groups[1].length) next[rightSlot] = paneStateWithTabs(groups[1], groups[1].includes(active) ? active : groups[1][0]);
  const nonFinderTree = groups[1].length
    ? splitNode('row', leafNode(leftSlot), leafNode(rightSlot), defaultSplitPercent)
    : leafNode(leftSlot);
  if (finderSlot) {
    next[finderSlot] = paneStateWithTabs([fileExplorerItemId], fileExplorerItemId);
    const finderFirst = finderLeadsExpandedPane(finderSlot, leftSlot);
    next[layoutTreeKey] = finderFirst
      ? splitNode('row', leafNode(finderSlot), nonFinderTree, fileExplorerSplitPercent)
      : splitNode('row', nonFinderTree, leafNode(finderSlot), 100 - fileExplorerSplitPercent);
  } else {
    next[layoutTreeKey] = nonFinderTree;
  }
  applyLayoutSlots(next, {focusSession: active, prune: false, message: 'split layout'});
}

function layoutWithFileExplorerDockedLeft(slots = layoutSlots) {
  const right = compactLayoutSlots(layoutWithoutItemFromSlots(fileExplorerItemId, slots, {preservePlaceholders: true}));
  const rightSlots = layoutSlotKeys(right).filter(slot => paneHasLayoutContent(slot, right));
  const next = emptyLayoutSlots();
  for (const slot of rightSlots) next[slot] = paneStateForLayoutSlot(slot, right);
  const used = new Set(rightSlots);
  const currentSlot = slotForItem(fileExplorerItemId, slots);
  let finderSlot = currentSlot && !used.has(currentSlot) ? currentSlot : null;
  if (!finderSlot) finderSlot = !used.has('left') ? 'left' : nextLayoutSlot(next);
  next[finderSlot] = paneStateWithTabs([fileExplorerItemId], fileExplorerItemId);
  next[layoutTreeKey] = rightSlots.length
    ? splitNode('row', leafNode(finderSlot), right[layoutTreeKey], fileExplorerSplitPercent)
    : leafNode(finderSlot);
  return compactLayoutSlots(next);
}

function dockFileExplorerPane() {
  applyLayoutSlots(layoutWithFileExplorerDockedLeft(), {
    focusSession: fileExplorerItemId,
    prune: false,
  });
}

function firstEmptyPane(slots = layoutSlots) {
  const placeholderSlot = layoutSlotKeys(slots).find(slot => paneIsPlaceholder(slot, slots));
  if (placeholderSlot) return placeholderSlot;
  return layoutSlotKeys(slots).length ? null : 'left';
}

function slotForNewSession() {
  const empty = firstEmptyPane();
  if (empty) return empty;
  const focusedSlot = focusedPanelItem ? slotForSession(focusedPanelItem) : null;
  if (focusedSlot) return focusedSlot;
  return 'left';
}

function slotForTabActivation(item) {
  const currentSlot = slotForSession(item);
  if (currentSlot) return currentSlot;
  return largestNonFileExplorerPaneSlot() || firstEmptyPane() || largestPaneSlot() || slotForNewSession();
}

async function activateTabInExistingPane(item) {
  if (!isLayoutItem(item)) return;
  if (isTmuxSession(item)) {
    const ensured = await ensureSession(item);
    if (!ensured) return;
  }
  const targetSlot = slotForTabActivation(item);
  if (!targetSlot) return;
  const currentSlot = slotForSession(item);
  if (currentSlot === targetSlot) {
    activatePaneTab(targetSlot, item);
    return;
  }
  await moveSessionToSlot(item, targetSlot, currentSlot, paneTabs(targetSlot).length);
}

function filesOnlySlotForSession(session) {
  const filesSlot = slotForSession(fileExplorerItemId);
  if (!filesSlot) return null;
  const stack = paneTabs(filesSlot).filter(item => item !== session);
  return stack.length === 1 && stack[0] === fileExplorerItemId ? filesSlot : null;
}

function slotForNewTmuxSession(session) {
  const currentSlot = slotForSession(session);
  if (currentSlot) return currentSlot;
  const empty = firstEmptyPane();
  if (empty) return empty;
  const targetSlot = largestNonFileExplorerPaneSlot();
  if (targetSlot) return targetSlot;
  return filesOnlySlotForSession(session) || largestPaneSlot() || slotForNewSession();
}

async function placeTmuxSession(session) {
  const currentSlot = slotForSession(session);
  if (currentSlot) {
    activatePaneTab(currentSlot, session);
    return;
  }
  const targetSlot = slotForNewTmuxSession(session);
  if (!targetSlot) return;
  if (paneIsPlaceholder(targetSlot) || !paneTabs(targetSlot).length) {
    await moveSessionToSlot(session, targetSlot, null);
    return;
  }
  if (isFileExplorerItem(activeItemForSide(targetSlot))) {
    await splitSessionAtSlot(session, targetSlot, 'right', null, fileExplorerSplitPercent);
    return;
  }
  await moveSessionToSlot(session, targetSlot, null, paneTabs(targetSlot).length);
}

// DOIT.6: File -> Finder toggles. Hide the Finder when it is already in the layout (same path as the
// Finder panel's close button), otherwise open/focus it. The menu's `checked` state tracks this.
function toggleFinderPane() {
  if (itemInLayout(fileExplorerItemId)) {
    removeSessionFromLayout(fileExplorerItemId);
    return false;
  }
  selectSession(fileExplorerItemId);
  return true;
}

async function openFileExplorerPane() {
  const currentSlot = slotForSession(fileExplorerItemId);
  if (currentSlot) {
    if (paneTabs(currentSlot).length === 1 && !fileExplorerNeedsLeftDock()) {
      activatePaneTab(currentSlot, fileExplorerItemId);
      return;
    }
    dockFileExplorerPane();
    return;
  }
  const empty = firstEmptyPane();
  if (empty) {
    if (layoutSlotKeys().includes(empty) && paneIsPlaceholder(empty)) {
      await splitSessionBesidePlaceholder(fileExplorerItemId, empty, 'left', fileExplorerSplitPercent);
    } else {
      await moveSessionToSlot(fileExplorerItemId, empty, null);
    }
    return;
  }
  const targetSlot = largestPaneSlot();
  if (targetSlot && paneTabs(targetSlot).length) {
    dockFileExplorerPane();
    return;
  }
  await moveSessionToSlot(fileExplorerItemId, slotForNewSession(), null);
}

async function splitSessionBesidePlaceholder(session, targetSlot, zone, pct = defaultSplitPercent) {
  if (!isLayoutItem(session) || !targetSlot || !['top', 'bottom', 'left', 'right'].includes(zone)) return;
  if (!paneIsPlaceholder(targetSlot)) {
    await splitSessionAtSlot(session, targetSlot, zone, null, pct);
    return;
  }
  if (isTmuxSession(session)) {
    const ensured = await ensureSession(session);
    if (!ensured) return;
  }
  const next = layoutWithoutItem(session);
  if (!next[layoutTreeKey]) next[layoutTreeKey] = leafNode(targetSlot);
  if (!next[targetSlot]) next[targetSlot] = emptyPlaceholderPaneState();
  const newSlot = nextLayoutSlot(next);
  next[newSlot] = paneStateWithTabs([session], session);
  const direction = zone === 'left' || zone === 'right' ? 'row' : 'column';
  const existingNode = leafNode(targetSlot);
  const newNode = leafNode(newSlot);
  const splitPct = splitPercentForNewItem(session, zone, pct);
  const replacement = zone === 'right' || zone === 'bottom'
    ? splitNode(direction, existingNode, newNode, splitPct)
    : splitNode(direction, newNode, existingNode, splitPct);
  next[layoutTreeKey] = replaceLayoutLeaf(next[layoutTreeKey], targetSlot, replacement);
  applyLayoutSlots(next, {focusSession: session, prune: false});
}

async function moveSessionToSlot(session, targetSlot, sourceSlot = null, insertIndex = 0) {
  if (!isLayoutItem(session) || !targetSlot) return;
  if (isTmuxSession(session)) {
    const ensured = await ensureSession(session);
    if (!ensured) return;
  }
  const next = layoutWithoutItem(session);
  if (!next[layoutTreeKey]) next[layoutTreeKey] = leafNode(targetSlot);
  if (!next[targetSlot]) next[targetSlot] = emptyPaneState();
  const tabs = next[targetSlot].tabs;
  const index = Math.max(0, Math.min(Number.isFinite(insertIndex) ? insertIndex : 0, tabs.length));
  tabs.splice(index, 0, session);
  recordTabActivation(session);
  // Enforce the per-pane tab cap: if this pane is now over the limit, auto-close the least-recently
  // used tabs (keeping the new active tab, the Finder, and any dirty editors).
  const evicted = tabsToEvictForCap(tabs, session);
  const keptTabs = evicted.length ? tabs.filter(item => !evicted.includes(item)) : tabs;
  next[targetSlot] = paneStateWithTabs(keptTabs, session);
  applyLayoutSlots(next, {
    focusSession: session,
    prune: false,
    message: evicted.length ? `${evicted.map(itemLabel).join(', ')} auto-closed (tab limit ${maxTabsPerPane()})` : '',
  });
}

async function dropSessionWithIntent(session, intent, sourceSlot = null) {
  if (isFileExplorerItem(session)) {
    await openFileExplorerPane();
    return;
  }
  if (intent?.boundary === 'gutter') {
    await splitSessionAtGutter(session, intent.splitPath, intent.zone, sourceSlot);
    return;
  }
  if (intent?.boundary === 'root') {
    await splitSessionAtLayoutBoundary(session, intent.zone, sourceSlot);
    return;
  }
  if (!intent?.targetSlot || intent.zone === 'middle') {
    await moveSessionToSlot(session, intent?.targetSlot || slotForNewSession(), sourceSlot);
    return;
  }
  await splitSessionAtSlot(session, intent.targetSlot, intent.zone, sourceSlot);
}

function splitPercentForNewItem(session, zone, pct = null) {
  if (pct !== null && pct !== undefined && pct !== '' && Number.isFinite(Number(pct))) return Number(pct);
  if (isFileExplorerItem(session) && (zone === 'left' || zone === 'right')) {
    return zone === 'left' ? fileExplorerSplitPercent : 100 - fileExplorerSplitPercent;
  }
  return defaultSplitPercent;
}

function shouldPreserveSourceSlotForSplit(sourceSlot, targetSlot) {
  return Boolean(sourceSlot && sourceSlot !== targetSlot && isFileExplorerItem(activeItemForSide(targetSlot)));
}

function dockedFileExplorerRootSplit(node, slots = layoutSlots) {
  if (!node || node.split !== 'row' || !Array.isArray(node.children) || node.children.length !== 2) return null;
  const finderIndex = node.children.findIndex(child => child?.slot && isFileExplorerItem(activeItemForSide(child.slot, slots)));
  if (finderIndex < 0) return null;
  return {
    finderIndex,
    contentIndex: finderIndex === 0 ? 1 : 0,
    pct: Number.isFinite(Number(node.pct)) ? Number(node.pct) : fileExplorerSplitPercent,
  };
}

function splitRootPreservingDockedFileExplorer(root, newNode, session, zone, pct = null, slots = layoutSlots) {
  const docked = (zone === 'top' || zone === 'bottom') ? dockedFileExplorerRootSplit(root, slots) : null;
  if (!docked) return null;
  const children = [...(root.children || [])];
  const contentNode = children[docked.contentIndex];
  if (!contentNode) return null;
  const splitPct = splitPercentForNewItem(session, zone, pct);
  children[docked.contentIndex] = zone === 'bottom'
    ? splitNode('column', contentNode, newNode, splitPct)
    : splitNode('column', newNode, contentNode, splitPct);
  return splitNode('row', children[0], children[1], docked.pct);
}

async function splitSessionAtSlot(session, targetSlot, zone, sourceSlot = null, pct = null) {
  if (!isLayoutItem(session) || !targetSlot || !['top', 'bottom', 'left', 'right'].includes(zone)) return;
  if (isTmuxSession(session)) {
    const ensured = await ensureSession(session);
    if (!ensured) return;
  }
  const next = layoutWithoutItem(session, {preserveEmptySlot: shouldPreserveSourceSlotForSplit(sourceSlot, targetSlot) ? sourceSlot : null});
  const targetTabs = paneTabs(targetSlot, next);
  if (!targetTabs.length) {
    await moveSessionToSlot(session, targetSlot, sourceSlot);
    return;
  }
  const newSlot = nextLayoutSlot(next);
  next[newSlot] = paneStateWithTabs([session], session);
  const direction = zone === 'left' || zone === 'right' ? 'row' : 'column';
  const existingNode = leafNode(targetSlot);
  const newNode = leafNode(newSlot);
  const splitPct = splitPercentForNewItem(session, zone, pct);
  const replacement = zone === 'right' || zone === 'bottom'
    ? splitNode(direction, existingNode, newNode, splitPct)
    : splitNode(direction, newNode, existingNode, splitPct);
  next[layoutTreeKey] = replaceLayoutLeaf(next[layoutTreeKey], targetSlot, replacement);
  applyLayoutSlots(next, {focusSession: session, prune: false});
}

async function splitSessionAtLayoutBoundary(session, zone, sourceSlot = null, pct = null) {
  if (!isLayoutItem(session) || !layoutSplitZone(zone)) return;
  if (isTmuxSession(session)) {
    const ensured = await ensureSession(session);
    if (!ensured) return;
  }
  const next = layoutWithoutItem(session);
  const root = next[layoutTreeKey] || legacyLayoutTree(next);
  if (!root) {
    await moveSessionToSlot(session, sourceSlot || slotForNewSession(), sourceSlot);
    return;
  }
  const newSlot = nextLayoutSlot(next);
  next[newSlot] = paneStateWithTabs([session], session);
  const newNode = leafNode(newSlot);
  const direction = layoutSplitDirectionForZone(zone);
  const splitPct = splitPercentForNewItem(session, zone, pct);
  next[layoutTreeKey] = splitRootPreservingDockedFileExplorer(root, newNode, session, zone, pct, next)
    || (zone === 'right' || zone === 'bottom'
    ? splitNode(direction, root, newNode, splitPct)
    : splitNode(direction, newNode, root, splitPct));
  applyLayoutSlots(next, {focusSession: session, prune: false});
}

async function splitSessionAtGutter(session, splitPath, zone, sourceSlot = null, pct = null) {
  if (!isLayoutItem(session) || !layoutSplitZone(zone)) return;
  if (isTmuxSession(session)) {
    const ensured = await ensureSession(session);
    if (!ensured) return;
  }
  const next = layoutWithoutItem(session);
  const root = next[layoutTreeKey] || legacyLayoutTree(next);
  const target = layoutNodeAtPath(splitPath, root);
  if (!root || !target?.children?.length) {
    await splitSessionAtLayoutBoundary(session, zone, sourceSlot, pct);
    return;
  }
  const newSlot = nextLayoutSlot(next);
  next[newSlot] = paneStateWithTabs([session], session);
  const replacement = splitLayoutNodeAtGutter(target, leafNode(newSlot), session, zone, pct);
  next[layoutTreeKey] = replaceLayoutNodeAtPath(root, splitPath, replacement);
  applyLayoutSlots(next, {focusSession: session, prune: false});
}

function layoutSplitZone(zone) {
  return zone === 'top' || zone === 'bottom' || zone === 'left' || zone === 'right';
}

function layoutSplitDirectionForZone(zone) {
  return zone === 'left' || zone === 'right' ? 'row' : 'column';
}

function splitLayoutNodeAtGutter(node, newNode, session, zone, pct = null) {
  const direction = node.split === 'column' ? 'column' : 'row';
  const first = node.children?.[0] || null;
  const second = node.children?.[1] || null;
  if (!first || !second) return newNode;
  const insertAfterFirst = direction === 'row' ? zone === 'left' : zone === 'top';
  if (insertAfterFirst) {
    const nestedZone = direction === 'row' ? 'right' : 'bottom';
    return splitNode(direction, splitNode(direction, first, newNode, splitPercentForNewItem(session, nestedZone, pct)), second, node.pct);
  }
  const nestedZone = direction === 'row' ? 'left' : 'top';
  return splitNode(direction, first, splitNode(direction, newNode, second, splitPercentForNewItem(session, nestedZone, pct)), node.pct);
}

function replaceLayoutLeaf(node, slot, replacement) {
  if (!node) return replacement;
  if (node.slot) return node.slot === slot ? replacement : node;
  const children = (node.children || []).map(child => replaceLayoutLeaf(child, slot, replacement));
  return splitNode(node.split === 'column' ? 'column' : 'row', children[0], children[1], node.pct);
}

function replaceLayoutNodeAtPath(node, path, replacement) {
  if (!path) return replacement;
  if (!node?.children) return node;
  const parts = String(path).split('.');
  const index = Number(parts[0]);
  if (!Number.isInteger(index) || index < 0 || index > 1) return node;
  const children = [...node.children];
  children[index] = replaceLayoutNodeAtPath(children[index], parts.slice(1).join('.'), replacement);
  return splitNode(node.split === 'column' ? 'column' : 'row', children[0], children[1], node.pct);
}

function activatePaneTab(side, session, options = {}) {
  if (!layoutSlotKeys().includes(side) || !itemInLayout(session)) return;
  recordTabActivation(session);
  const previous = activeItemForSide(side);
  if (previous && previous !== session && typeof captureFileEditorPanelViewStateForItem === 'function') {
    captureFileEditorPanelViewStateForItem(previous);
  }
  if (isFileEditorItem(session)) {
    activeFile = fileItemPath(session);
    updateFileExplorerCurrentFileHighlight();
  }
  // DOIT.21: a user-initiated tab switch IS navigation — record EVERY tab kind (file, terminal, Finder,
  // Prefs, …) so Back returns to the previous tab worked on, not just files. (No-op while navigating.)
  if (options.userInitiated === true) recordEditorNav(session);
  setFocusedPanelItem(session);
  if (activeItemForSide(side) === session) {
    focusPanel(session, {userInitiated: options.userInitiated === true});
    return;
  }
  const next = emptyLayoutSlots();
  next[layoutTreeKey] = layoutSlots[layoutTreeKey];
  for (const key of layoutSlotKeys()) next[key] = paneStateForLayoutSlot(key);
  next[side].active = session;
  applyLayoutSlots(next, {focusSession: session});
  if (isPreferencesItem(session) && options.userInitiated === true && autoFocusEnabled) {
    focusFreshPreferencesSearchSoon();
  }
  if (options.userInitiated && isTmuxSession(session)) focusTerminalFromUserAction(session, 25);
}

async function selectSession(session) {
  if (isFileEditorItem(session)) {
    activeFile = fileItemPath(session);
    updateFileExplorerCurrentFileHighlight();
  }
  const shouldFocusPreferencesSearch = isPreferencesItem(session);
  if (isFileExplorerItem(session)) {
    await openFileExplorerPane();
    scheduleFileExplorerActiveTabSync();
    return;
  }
  if (activeSessions.includes(session)) {
    focusPanel(session, {userInitiated: true});
    return;
  }
  if (isTmuxSession(session) && filesOnlySlotForSession(session)) {
    await placeTmuxSession(session);
    return;
  }
  await activateTabInExistingPane(session);
  if (shouldFocusPreferencesSearch) focusFreshPreferencesSearchSoon();
}

function sessionAgentKind(session) {
  const info = transcriptMeta.sessions?.[session];
  const agent = info?.agents?.find(item => item.transcript) || info?.agents?.[0];
  const kind = String(agent?.kind || '').toLowerCase();
  return kind === 'claude' || kind === 'codex' ? kind : '';
}

function agentIcon(kind) {
  if (kind === 'codex') {
    return `<span class="agent-icon codex" aria-label="Codex" title="Codex">${codexIcon()}</span>`;
  }
  if (kind === 'claude') {
    return `<span class="agent-icon claude" aria-label="Claude" title="Claude">${claudeIcon()}</span>`;
  }
  return '';
}

function codexIcon() {
  return `<svg viewBox="0 0 24 24" aria-hidden="true">
    <path fill="#667ef8" d="M7.3 20.8c-3.1 0-5.7-2.4-5.9-5.5-.2-2.4 1.1-4.6 3.1-5.7C4.8 5.9 7.9 3 11.8 3c3.3 0 6.2 2.2 7 5.4 2.4.7 4 2.8 4 5.4 0 3.2-2.6 5.8-5.8 5.8-.9 1.1-2.2 1.8-3.8 1.8-1.2 0-2.3-.4-3.1-1.1-.8.3-1.8.5-2.8.5z"/>
    <path fill="#fff" d="M6.4 8.2c.5-.5 1.2-.5 1.7 0l2.8 2.8c.5.5.5 1.2 0 1.7l-2.8 2.8c-.5.5-1.2.5-1.7 0s-.5-1.2 0-1.7l1.9-1.9-1.9-1.9c-.5-.5-.5-1.3 0-1.8zM13 13.2h5.1c.7 0 1.2.5 1.2 1.2s-.5 1.2-1.2 1.2H13c-.7 0-1.2-.5-1.2-1.2s.5-1.2 1.2-1.2z"/>
  </svg>`;
}

function claudeIcon() {
  return `<svg viewBox="0 0 24 24" aria-hidden="true">
    <rect width="24" height="24" rx="5.5" fill="#cf7554"/>
    <g fill="#fff7f1">
      <path d="M11.1 2.4h1.8l1.1 7.9-2 .6-2-.6 1.1-7.9z"/>
      <path d="m17.8 4.3 1.4 1.1-4.3 6.7-2.1-1.3 5-6.5z"/>
      <path d="m21.5 10.2.3 1.8-8.2 2-1-2.3 8.9-1.5z"/>
      <path d="m20.2 16.8-1.1 1.4-6.7-4.3 1.3-2.1 6.5 5z"/>
      <path d="m13.8 21.5-1.8.3-2-8.2 2.3-1 1.5 8.9z"/>
      <path d="m6.2 19.7-1.4-1.1 4.3-6.7 2.1 1.3-5 6.5z"/>
      <path d="m2.5 13.8-.3-1.8 8.2-2 1 2.3-8.9 1.5z"/>
      <path d="m3.8 7.2 1.1-1.4 6.7 4.3-1.3 2.1-6.5-5z"/>
      <circle cx="12" cy="12" r="2.2"/>
    </g>
  </svg>`;
}

function agentName(kind) {
  return kind === 'codex' ? 'Codex' : kind === 'claude' ? 'Claude' : kind === 'term' ? 'Term' : '';
}

function numericSessionName(session) {
  const match = String(session).match(/^[1-9]\d*$/);
  return match ? Number(match[0]) : null;
}

function sessionLabelAssignments() {
  const assigned = new Map();
  const used = new Set();
  for (const session of visibleSessions) {
    const numeric = numericSessionName(session);
    if (numeric !== null) {
      assigned.set(session, String(numeric));
      used.add(numeric);
    }
  }

  const backfill = [];
  for (let value = 9; value >= 1; value -= 1) {
    if (!used.has(value)) backfill.push(value);
  }

  let overflow = 10;
  for (const session of visibleSessions) {
    if (assigned.has(session)) continue;
    let label = backfill.length ? backfill.shift() : overflow;
    while (used.has(label)) label += 1;
    assigned.set(session, String(label));
    used.add(label);
    if (label >= overflow) overflow = label + 1;
  }
  return assigned;
}

function sessionForLabel(label) {
  const text = String(label);
  for (const [session, assignedLabel] of sessionLabelAssignments()) {
    if (assignedLabel === text) return session;
  }
  return null;
}

function sessionLabel(session) {
  const assigned = sessionLabelAssignments().get(session);
  if (assigned) return assigned;
  const numeric = numericSessionName(session);
  if (numeric !== null) return String(numeric);
  return String(session);
}

function shortText(value, limit = 96) {
  const text = String(value || '').replace(/\s+/g, ' ').trim();
  if (text.length <= limit) return text;
  return `${text.slice(0, Math.max(0, limit - 3))}...`;
}

function shortBranch(value) {
  const text = String(value || '');
  if (text.length <= 46) return text;
  return `${text.slice(0, 18)}...${text.slice(-25)}`;
}

function linkHtml(url, label, title = '', className = '') {
  if (!url) return `<span>${esc(label)}</span>`;
  const titleAttr = title ? ` title="${esc(title)}"` : '';
  const classAttr = className ? ` class="${esc(className)}"` : '';
  return `<a href="${esc(url)}" target="_blank" rel="noreferrer noopener" draggable="false"${titleAttr}${classAttr}>${esc(label)}</a>`;
}

function pullRequestStatusLabel(pr) {
  if (!pr) return '';
  if (pr.status_label) return pr.status_label;
  if (pr.source_only) return '';
  if (pr.draft) return 'draft';
  if (pr.merged || pr.merged_at) return 'merged';
  return pr.state || '';
}

function pullRequestStatusDisplay(pr) {
  const status = pullRequestStatusLabel(pr);
  if (!status) return '';
  const key = status.toLowerCase();
  if (key === 'unknown') return '';
  if (key === 'merged') return 'MERGED';
  if (key === 'draft') return 'DRAFT';
  if (key === 'closed') return 'CLOSED';
  if (key === 'open') return 'OPEN';
  return status.replace(/\bci\b/gi, 'CI').toUpperCase();
}

function pullRequestLinkLabel(pr) {
  const status = pullRequestStatusDisplay(pr);
  return `PR #${pr.number}${status ? ` ${status}` : ''}`;
}

function pullRequestStatusClass(pr) {
  const status = pullRequestStatusLabel(pr).toLowerCase();
  if (status.includes('failing')) return 'pr-status-failing';
  if (status.includes('pending')) return 'pr-status-pending';
  if (status.includes('passing')) return 'pr-status-passing';
  if (status.includes('merged')) return 'pr-status-merged';
  if (status.includes('draft')) return 'pr-status-draft';
  if (status.includes('closed')) return 'pr-status-closed';
  return 'pr-status-unknown';
}

function pullRequestCiStatusClass(pr) {
  const state = String(pr?.checks?.state || '').toLowerCase();
  if (['success', 'passing', 'passed', 'green'].includes(state)) return 'pr-status-passing';
  if (['failure', 'failing', 'failed', 'red', 'error', 'cancelled', 'timed_out', 'action_required'].includes(state)) return 'pr-status-failing';
  if (['pending', 'queued', 'in_progress', 'running', 'waiting', 'requested'].includes(state)) return 'pr-status-pending';
  return pullRequestStatusClass(pr);
}

function pullRequestStatusIndicatorHtml(session, pr) {
  if (!pr?.number) return '';
  const status = pullRequestStatusLabel(pr).toLowerCase();
  if (!['merged', 'draft', 'closed'].includes(status)) return '';
  return `<span class="${metadataBadgeClasses(session, 'status', `ci-indicator tab-symbol ${pullRequestStatusClass(pr)}`)}">${pullRequestStatusDisplay(pr)}</span>`;
}

function pullRequestCiIndicatorHtml(session, pr) {
  if (pullRequestStatusLabel(pr).toLowerCase() === 'merged') return '';
  const state = pr?.checks?.state;
  if (!state || state === 'unknown') return '';
  return `<span class="${metadataBadgeClasses(session, 'ci', `ci-indicator tab-symbol ${pullRequestCiStatusClass(pr)}`)}">CI</span>`;
}

function pullRequestNumberIndicatorHtml(session, pr) {
  if (!pr?.number) return '';
  // No native title — the rich custom session popover already shows PR #, CI, and review state
  // (DOIT.6: avoid a duplicate browser tooltip alongside the popover).
  return `<span class="ci-indicator tab-symbol pr-number-chip">#${esc(String(pr.number))}</span>`;
}

// #38: GitHub reviewDecision (APPROVED / CHANGES_REQUESTED / REVIEW_REQUIRED) per PR.
function pullRequestReviewDecision(pr) {
  return String(pr?.review_decision || '').toUpperCase();
}

function pullRequestApprovalClass(decision) {
  if (decision === 'APPROVED') return 'pr-review-approved';
  if (decision === 'CHANGES_REQUESTED') return 'pr-review-changes';
  if (decision === 'REVIEW_REQUIRED') return 'pr-review-required';
  return '';
}

function pullRequestApprovalLabel(decision) {
  if (decision === 'APPROVED') return 'Approved';
  if (decision === 'CHANGES_REQUESTED') return 'Changes';
  if (decision === 'REVIEW_REQUIRED') return 'Review';
  return '';
}

function pullRequestApprovalIndicatorHtml(session, pr) {
  if (!pr?.number) return '';
  // No review badge once the PR is merged/closed (review state no longer actionable).
  if (['merged', 'closed'].includes(pullRequestStatusLabel(pr).toLowerCase())) return '';
  const decision = pullRequestReviewDecision(pr);
  const cls = pullRequestApprovalClass(decision);
  if (!cls) return '';
  const label = pullRequestApprovalLabel(decision);
  // No native title — the session popover carries the review state (DOIT.6: no duplicate tooltip).
  return `<span class="${metadataBadgeClasses(session, 'review', `ci-indicator tab-symbol pr-review-chip ${cls}`)}">${esc(label)}</span>`;
}

// DOIT.6: review status + reviewer(s) for the session popover PR row ("Approved by alice" /
// "Changes requested by bob" / "Review required"). Reuses the meta-pr-status color classes.
function pullRequestReviewInlineHtml(pr) {
  const decision = pullRequestReviewDecision(pr);
  if (!decision) return '';
  const reviewers = Array.isArray(pr?.review_reviewers) ? pr.review_reviewers : [];
  const loginsFor = state => reviewers
    .filter(reviewer => String(reviewer?.state || '').toUpperCase() === state)
    .map(reviewer => reviewer.login)
    .filter(Boolean);
  const by = logins => (logins.length ? t('pr.by', {logins: esc(logins.join(', '))}) : '');
  if (decision === 'APPROVED') return `<span class="meta-pr-status pr-status-passing">${esc(t('pr.approved'))}${by(loginsFor('APPROVED'))}</span>`;
  if (decision === 'CHANGES_REQUESTED') return `<span class="meta-pr-status pr-status-failing">${esc(t('pr.changesRequested'))}${by(loginsFor('CHANGES_REQUESTED'))}</span>`;
  if (decision === 'REVIEW_REQUIRED') return `<span class="meta-muted">${esc(t('pr.reviewRequired'))}</span>`;
  return '';
}

function pullRequestLinkHtml(pr) {
  return linkHtml(pr.url, pullRequestLinkLabel(pr), pr.title || pr.description || '', pullRequestStatusClass(pr));
}

function pullRequestAuthorHtml(pr) {
  const author = String(pr?.author_login || '').trim();
  return author ? `<span class="meta-muted">by ${esc(author)}</span>` : '';
}

function pullRequestColumnLinkHtml(pr) {
  const status = pullRequestStatusDisplay(pr);
  const label = `#${pr.number}${status ? ` ${status}` : ''}`;
  return linkHtml(pr.url, label, pr.title || pr.description || '', pullRequestStatusClass(pr));
}

function pullRequestChecksHtml(pr) {
  const checks = pr?.checks;
  if (!checks || !checks.state || checks.state === 'unknown') return '';
  const cls = pullRequestCiStatusClass(pr);
  const parts = [`<span class="meta-pr-status ${cls}">${esc(checks.summary || `CI ${checks.state}`)}</span>`];
  const checkLinks = items => (items || []).map(item => (
    item?.name ? linkHtml(item.url || '', item.name, item.state || '') : ''
  )).filter(Boolean).join(', ');
  const failing = checkLinks(checks.failing);
  const pending = checkLinks(checks.pending);
  if (failing) parts.push(`<span class="meta-muted">failing: ${failing}</span>`);
  if (pending) parts.push(`<span class="meta-muted">pending: ${pending}</span>`);
  if (Number.isFinite(checks.total)) parts.push(`<span class="meta-muted">${checks.total} checks</span>`);
  return metaJoin(parts);
}

function panelFullPath(session, info) {
  const project = info?.project || {};
  const git = project.git;
  const panes = Array.isArray(info?.panes) ? info.panes : [];
  const nonHomePane = panes.find(pane => pane?.current_path && pane.current_path !== homePath && !['claude', 'codex'].includes(String(pane.command || '').toLowerCase()));
  if (nonHomePane?.current_path) return nonHomePane.current_path;
  if (git?.cwd) return git.cwd;
  if (git?.root) return git.root;
  if (info?.selected_pane?.current_path) return info.selected_pane.current_path;
  return '';
}

function compactHomePath(path) {
  const text = String(path || '').replace(/\/+$/, '');
  const home = String(homePath || '').replace(/\/+$/, '');
  if (!text || !home) return text;
  if (text === home) return '~';
  if (text.startsWith(`${home}/`)) return `~/${text.slice(home.length + 1)}`;
  return text;
}

function projectMetaHtml(session, info) {
  const project = info?.project || {};
  const git = project.git;
  const parts = [];
  const fullPath = panelFullPath(session, info);
  if (!git) {
    if (fullPath) parts.push(`<span class="meta-path">${esc(compactHomePath(fullPath))}</span>`);
    parts.push('<span class="meta-muted">no git checkout detected</span>');
    return metaJoin(parts);
  }
  const pr = displayPullRequest(info);
  if (pr?.number) parts.push(pullRequestLinkHtml(pr));
  if (git.branch) parts.push(`<span class="meta-branch">${esc(shortBranch(git.branch))}</span>`);
  if (fullPath) parts.push(`<span class="meta-path">${esc(compactHomePath(fullPath))}</span>`);
  if (Number.isFinite(git.behind) && git.behind > 0) parts.push(`<span class="meta-muted">behind ${git.behind}</span>`);
  if (Number.isFinite(git.ahead) && git.ahead > 0) parts.push(`<span class="meta-muted">ahead ${git.ahead}</span>`);
  if (Number.isFinite(git.dirty_count) && git.dirty_count > 0) parts.push(`<span class="meta-muted">dirty ${git.dirty_count}</span>`);
  if (pr?.number) {
    if (pr.checks?.state && pr.checks.state !== 'unknown') {
      parts.push(`<span class="meta-pr-status ${pullRequestCiStatusClass(pr)}">${esc(pr.checks.summary || pullRequestStatusLabel(pr))}</span>`);
    }
  }
  for (const issue of project.linear || []) {
    const state = issue.state ? ` ${issue.state}` : '';
    parts.push(linkHtml(issue.url, `${issue.identifier}${state}`, issue.title || ''));
  }
  const desc = pr?.title || pr?.description || (project.linear || []).find(issue => issue.title)?.title || '';
  if (desc) parts.push(`<span class="meta-desc">${esc(shortText(desc, 160))}</span>`);
  return parts.length ? metaJoin(parts) : '<span class="meta-muted">git checkout detected</span>';
}

function summaryContextHtml(session, info, agent) {
  const lines = [];
  const pane = info?.selected_pane;
  if (agent) {
    lines.push(summaryContextLine('agent', `${agent.kind || 'agent'} pid=${agent.pid || ''}${agent.status ? ` status=${agent.status}` : ''}`));
    if (agent.transcript) lines.push(summaryContextLine('transcript', agent.transcript));
    if (agent.error && !agent.transcript) lines.push(summaryContextLine('transcript', agent.error));
  } else {
    lines.push(summaryContextLine('agent', 'not detected'));
  }
  if (pane) lines.push(summaryContextLine('pane', `${pane.command || 'tmux'} ${pane.target || session} in ${pane.current_path || ''}`));

  const project = info?.project || {};
  const git = project.git;
  if (git) {
    lines.push(summaryContextLine('branch', `${git.branch || 'unknown'}${git.upstream ? ` -> ${git.upstream}` : ''}`));
    if (git.root) lines.push(summaryContextLine('repo', git.root));
    if (git.head) lines.push(summaryContextLine('head', git.head));
  } else {
    lines.push(summaryContextLine('repo', 'no git checkout detected'));
  }
  const pr = displayPullRequest(info);
  if (pr?.number) {
    const label = pullRequestLinkLabel(pr);
    lines.push(summaryContextLine('github', `${label} ${pr.title || pr.description || ''}`, pr.url, label, pullRequestStatusClass(pr)));
  }
  for (const issue of project.linear || []) {
    const label = `${issue.identifier}${issue.state ? ` ${issue.state}` : ''}`;
    lines.push(summaryContextLine('linear', `${label} ${issue.title || ''}`, issue.url, issue.identifier));
  }
  return lines.join('');
}

function summaryContextLine(label, text, url = '', linkLabel = '', linkClass = '') {
  const value = url && linkLabel
    ? `${linkHtml(url, linkLabel, text, linkClass)} ${esc(text.replace(linkLabel, '').trim())}`
    : esc(text);
  return `<div class="summary-context-line"><span class="summary-context-label">${esc(label)}:</span> ${value}</div>`;
}

async function ensureSession(session) {
  if (readOnlyMode) return true;
  try {
    const response = await apiFetch(`/api/ensure-session?session=${encodeURIComponent(session)}`, {method: 'POST'});
    const payload = await response.json();
    if (!response.ok) {
      statusErr(`${esc(payload.error || 'session create failed')}`);
      return false;
    }
    statusEl.innerHTML = payload.created
      ? `<span class="ok">created ${esc(sessionLabel(session))} with Claude</span>`
      : `<span class="ok">${esc(sessionLabel(session))} ready</span>`;
    return true;
  } catch (error) {
    statusErr(`session check failed: ${esc(error)}`);
    return false;
  }
}

async function createNextSession(agent) {
  if (readOnlyMode) {
    statusErr('readonly access cannot create sessions');
    return;
  }
  const agentLabel = agentName(agent) || 'agent';
  statusEl.textContent = `creating ${agentLabel} session...`;
  try {
    const response = await apiFetch(`/api/create-session?agent=${encodeURIComponent(agent)}`, {method: 'POST'});
    const payload = await response.json();
    if (!response.ok) {
      statusErr(`${esc(payload.error || 'session create failed')}`);
      return;
    }
    const previousActive = activeSessions.slice();
    updateSessionList(payload.sessions || []);
    renderSessionButtons();
    renderPanels(previousActive);
    await placeTmuxSession(payload.session);
    await ensureTerminalRunning(payload.session);
    refreshTranscripts();
    renderAutoApproveButtons();
    statusOk(`created ${esc(sessionLabel(payload.session))} (${esc(payload.session)}) with ${esc(agentName(payload.agent) || agentLabel)}`);
  } catch (error) {
    statusErr(`session create failed: ${esc(error)}`);
  }
}

function tmuxSessionNameError(name) {
  const text = String(name || '').trim();
  if (!text) return 'session name is required';
  if (text.length > 64) return 'session name must be 64 characters or fewer';
  // Keep in sync with TMUX_SESSION_NAME_RE in yolomux_lib/app.py.
  if (!/^[A-Za-z0-9_. -]+$/.test(text)) return 'session name may contain only letters, numbers, spaces, dot, dash, and underscore';
  return '';
}

function rekeyMap(map, oldKey, newKey) {
  if (!map.has(oldKey) || oldKey === newKey) return;
  if (!map.has(newKey)) map.set(newKey, map.get(oldKey));
  map.delete(oldKey);
}

function stopSessionUi(session) {
  const item = terminals.get(session);
  if (item) closeTerminalItem(session, item);
  terminals.delete(session);
  stopTranscriptStream(session);
  stopSummaryStream(session);
  const panel = panelNodes.get(session);
  if (panel) panel.remove();
  panelNodes.delete(session);
}

function replaceSessionMetadata(oldSession, newSession) {
  for (const map of [
    autoApproveStates,
    sessionStateKeys,
    notificationLastSent,
    attentionAlertTimers,
    metadataBadgePulseUntil,
    uploadResultsBySession,
    uploadCleanupTimers,
    pasteCounters,
    // DOIT.6 #73: carry the per-pane LRU timestamp across a session rename too, or the renamed tab's
    // eviction ordering glitches (it reads as never-activated).
    tabLastActivatedAt,
  ]) {
    rekeyMap(map, oldSession, newSession);
  }
  if (transcriptMeta.sessions?.[oldSession]) {
    transcriptMeta.sessions = {
      ...(transcriptMeta.sessions || {}),
      [newSession]: transcriptMeta.sessions[newSession] || transcriptMeta.sessions[oldSession],
    };
    delete transcriptMeta.sessions[oldSession];
  }
  if (Array.isArray(transcriptMeta.session_order)) {
    transcriptMeta.session_order = transcriptMeta.session_order.map(item => item === oldSession ? newSession : item);
  }
}

function replaceTmuxSessionInClient(oldSession, newSession, nextSessions) {
  const next = normalizedSessionOrder(nextSessions) || sessions.map(item => item === oldSession ? newSession : item);
  stopSessionUi(oldSession);
  replaceSessionMetadata(oldSession, newSession);
  setSessionOrder(next);
  if (focusedTerminal === oldSession) focusedTerminal = newSession;
  if (focusedPanelItem === oldSession) focusedPanelItem = newSession;
  if (lastFocusedTmuxSession === oldSession) lastFocusedTmuxSession = newSession;
  applyLayoutSlots(layoutWithReplacedItem(oldSession, newSession), {focusSession: newSession, prune: false});
}

function closeSessionRenameDialog() {
  if (!sessionRenameDialog) return;
  sessionRenameDialog.remove();
  sessionRenameDialog = null;
  document.removeEventListener('keydown', sessionRenameDialogKeydown, true);
}

function sessionRenameDialogKeydown(event) {
  if (event.key === 'Escape') closeSessionRenameDialog();
}

function showSessionRenameDialog(session) {
  if (readOnlyMode) {
    statusErr('readonly access cannot rename sessions');
    return false;
  }
  if (!isTmuxSession(session)) return false;
  closeContextMenus();
  closeAppMenus();
  closeSessionRenameDialog();
  const overlay = document.createElement('div');
  overlay.className = 'session-rename-backdrop';
  overlay.setAttribute('role', 'presentation');
  overlay.innerHTML = `
    <form class="session-rename-dialog" role="dialog" aria-modal="true" aria-label="${esc(t('rename.aria'))}">
      <div class="session-rename-title">${esc(t('rename.title', {name: `${sessionLabel(session)} ${session}`}))}</div>
      <input class="session-rename-input" name="sessionName" value="${esc(session)}" aria-label="${esc(t('rename.inputAria'))}" autocomplete="off">
      <div class="session-rename-error" hidden></div>
      <div class="session-rename-actions">
        <button type="button" class="session-rename-cancel">${esc(t('rename.cancel'))}</button>
        <button type="submit" class="session-rename-submit">${esc(t('rename.submit'))}</button>
      </div>
    </form>`;
  const form = overlay.querySelector('form');
  const input = overlay.querySelector('.session-rename-input');
  const errorNode = overlay.querySelector('.session-rename-error');
  const cancel = overlay.querySelector('.session-rename-cancel');
  const showError = message => {
    errorNode.textContent = message;
    errorNode.hidden = false;
  };
  overlay.addEventListener('pointerdown', event => {
    if (event.target === overlay) closeSessionRenameDialog();
  });
  cancel.addEventListener('click', closeSessionRenameDialog);
  form.addEventListener('submit', async event => {
    event.preventDefault();
    const nextName = input.value.trim();
    const nameError = tmuxSessionNameError(nextName);
    if (nameError) {
      showError(nameError);
      input.focus();
      return;
    }
    errorNode.hidden = true;
    const renamed = await renameTmuxSession(session, nextName);
    if (!renamed) {
      showError('rename failed; see status line');
      input.focus();
    }
  });
  document.body.appendChild(overlay);
  sessionRenameDialog = overlay;
  document.addEventListener('keydown', sessionRenameDialogKeydown, true);
  setTimeout(() => {
    input.focus();
    input.select();
  }, 0);
  return true;
}

async function renameTmuxSession(session, proposedName) {
  if (readOnlyMode) {
    statusErr('readonly access cannot rename sessions');
    return false;
  }
  if (!isTmuxSession(session)) return false;
  if (proposedName === undefined) return showSessionRenameDialog(session);
  const rawName = proposedName;
  const newName = String(rawName || '').trim();
  const nameError = tmuxSessionNameError(newName);
  if (nameError) {
    statusErr(`${esc(nameError)}`);
    return false;
  }
  if (newName === session) {
    closeSessionRenameDialog();
    return true;
  }
  statusEl.textContent = `renaming ${sessionLabel(session)}...`;
  try {
    const response = await apiFetch(`/api/rename-session?session=${encodeURIComponent(session)}&new_name=${encodeURIComponent(newName)}`, {method: 'POST'});
    const payload = await response.json();
    if (!response.ok) {
      statusErr(`${esc(payload.error || 'session rename failed')}`);
      return false;
    }
    const renamed = payload.new_session || newName;
    replaceTmuxSessionInClient(session, renamed, payload.sessions);
    closeSessionRenameDialog();
    await ensureTerminalRunning(renamed);
    refreshTranscripts();
    renderAutoApproveButtons();
    statusOk(`renamed ${esc(session)} to ${esc(renamed)}`);
    return true;
  } catch (error) {
    statusErr(`session rename failed: ${esc(error)}`);
    return false;
  }
}

async function killTmuxSession(session) {
  if (readOnlyMode) {
    statusErr('readonly access cannot kill sessions');
    return false;
  }
  if (!isTmuxSession(session)) return false;
  if (!window.confirm(`Kill tmux session ${sessionLabel(session)}?`)) return false;
  statusEl.textContent = `killing ${sessionLabel(session)}...`;
  try {
    const response = await apiFetch(`/api/kill-session?session=${encodeURIComponent(session)}`, {method: 'POST'});
    const payload = await response.json();
    if (!response.ok) {
      statusErr(`${esc(payload.error || 'session kill failed')}`);
      return false;
    }
    const previousActive = activeSessions.slice();
    stopSessionUi(session);
    const sessionsChanged = updateSessionList(payload.sessions || []);
    autoApproveStates.delete(session);
    updateDocumentTitle();
    renderSessionButtons();
    renderPanels(previousActive);
    if (sessionsChanged) renderPaneTabStrips();
    refreshTranscripts();
    renderAutoApproveButtons();
    statusOk(`killed ${esc(sessionLabel(session))}`);
    return true;
  } catch (error) {
    statusErr(`session kill failed: ${esc(error)}`);
    return false;
  }
}

function focusPanel(session, options = {}) {
  const panel = document.getElementById(`panel-${session}`);
  if (!panel) return;
  if (options.userInitiated === true || options.scrollIntoView === true) {
    panel.scrollIntoView({block: 'nearest', inline: 'nearest'});
  }
  if (isFileEditorItem(session)) {
    focusedTerminal = null;
    setFocusedPanelItem(session);
    if (autoFocusEnabled) {
      requestFileEditorPanelFocus(session);
      focusFileEditorPanelIfReady(panel, session);
    }
    return;
  }
  if (isVirtualItem(session)) {
    focusedTerminal = null;
    setFocusedPanelItem(session);
    if (isPreferencesItem(session) && options.userInitiated === true && autoFocusEnabled) {
      focusFreshPreferencesSearchSoon(panel);
    }
    return;
  }
  activateTab(session, 'terminal', {userInitiated: options.userInitiated === true});
}

function fitTerminal(session) {
  const item = terminals.get(session);
  if (!item || !item.term || !item.container) return;
  if (!terminalIsVisible(session, item.container)) return;
  const size = estimateTerminalSize(item.container, item.term);
  const changed = item.term.cols !== size.cols || item.term.rows !== size.rows;
  item.term.resize(size.cols, size.rows);
  if (changed) scheduleRemoteResize(session);
  refreshTerminal(session);
}

function sendRemoteResize(session) {
  const item = terminals.get(session);
  if (!item?.term || item?.socket?.readyState !== WebSocket.OPEN) return;
  item.socket.send(JSON.stringify({type: 'resize', cols: item.term.cols, rows: item.term.rows}));
}

function scheduleRemoteResize(session, delay = remoteResizeDelayMs) {
  const item = terminals.get(session);
  if (!item) return;
  if (item.resizeTimer) clearTimeout(item.resizeTimer);
  item.resizeTimer = setTimeout(() => {
    item.resizeTimer = null;
    sendRemoteResize(session);
  }, delay);
}

function refreshTerminal(session) {
  const item = terminals.get(session);
  if (!item?.term) return;
  requestAnimationFrame(() => {
    try { item.term.refresh(0, Math.max(0, item.term.rows - 1)); } catch (_) {}
  });
}

function terminalIsVisible(session, container) {
  const pane = document.getElementById(`terminal-pane-${session}`);
  return Boolean(
    pane?.classList.contains('active')
    && container.clientWidth > 40
    && container.clientHeight > 40
  );
}

function scheduleFit(session) {
  const item = terminals.get(session);
  if (item) {
    if (item.fitFrame) cancelAnimationFrame(item.fitFrame);
    if (item.fitTimer) clearTimeout(item.fitTimer);
    if (item.fitFinalTimer) clearTimeout(item.fitFinalTimer);
    item.fitFrame = requestAnimationFrame(() => {
      item.fitFrame = 0;
      fitTerminal(session);
    });
    item.fitTimer = setTimeout(() => {
      item.fitTimer = 0;
      fitTerminal(session);
    }, 80);
    item.fitFinalTimer = setTimeout(() => {
      item.fitFinalTimer = 0;
      fitTerminal(session);
    }, 250);
    return;
  }
  requestAnimationFrame(() => fitTerminal(session));
}

function observeTerminalResize(session, container) {
  const oldObserver = resizeObservers.get(session);
  if (oldObserver) oldObserver.disconnect();
  if (!window.ResizeObserver) return;
  const observer = new ResizeObserver(() => scheduleFit(session));
  observer.observe(container);
  resizeObservers.set(session, observer);
}

function enableTerminalScroll(session, term, container) {
  container.addEventListener('wheel', event => {
    if (event.ctrlKey && event.deltaY !== 0) {
      event.preventDefault();
      event.stopPropagation();
      return;
    }
    const signedLines = terminalWheelSignedLines(event, term.rows);
    if (!signedLines) return;
    event.preventDefault();
    event.stopPropagation();
    const item = terminals.get(session);
    if (!readOnlyMode && item?.socket?.readyState === WebSocket.OPEN) {
      queueTmuxScroll(item, signedLines);
      return;
    }
    queueLocalTerminalScroll(term, signedLines);
  }, {capture: true, passive: false});
}

function terminalWheelSignedLines(event, rows = 0) {
  const deltaY = Number(event?.deltaY);
  if (!Number.isFinite(deltaY) || deltaY === 0 || event?.ctrlKey) return 0;
  const direction = deltaY < 0 ? -1 : 1;
  const pageLines = Math.max(1, Math.floor((Number(rows) || 0) * terminalWheelPageFraction));
  if (event?.shiftKey) return direction * pageLines;
  const magnitude = Math.abs(deltaY);
  let lines;
  if (event?.deltaMode === 1) lines = magnitude;
  else if (event?.deltaMode === 2) lines = magnitude * pageLines;
  else lines = magnitude / terminalWheelPixelLinePx;
  return direction * Math.min(terminalWheelMaxLinesPerEvent, lines);
}

function queueTmuxScroll(item, signedLines) {
  item.pendingScrollLines = (item.pendingScrollLines || 0) + signedLines;
  if (item.scrollTimer) return;
  item.scrollTimer = setTimeout(() => {
    item.scrollTimer = null;
    const signed = item.pendingScrollLines || 0;
    item.pendingScrollLines = 0;
    if (!signed || item.socket?.readyState !== WebSocket.OPEN) return;
    const direction = signed < 0 ? 'up' : 'down';
    const lines = Math.max(1, Math.min(80, Math.ceil(Math.abs(signed))));
    item.socket.send(JSON.stringify({type: 'tmux-scroll', direction, lines}));
  }, 30);
}

function queueLocalTerminalScroll(term, signedLines) {
  term.pendingWheelScrollLines = (term.pendingWheelScrollLines || 0) + signedLines;
  if (term.wheelScrollTimer) return;
  term.wheelScrollTimer = setTimeout(() => {
    term.wheelScrollTimer = null;
    const signed = term.pendingWheelScrollLines || 0;
    term.pendingWheelScrollLines = 0;
    if (!signed) return;
    const direction = signed < 0 ? -1 : 1;
    const lines = Math.max(1, Math.min(80, Math.ceil(Math.abs(signed))));
    term.scrollLines(direction * lines);
  }, 30);
}

function closeTerminalItem(session, item) {
  item.manualClose = true;
  if (item.reconnectTimer) clearTimeout(item.reconnectTimer);
  if (item.resizeTimer) clearTimeout(item.resizeTimer);
  if (item.scrollTimer) clearTimeout(item.scrollTimer);
  const observer = resizeObservers.get(session);
  if (observer) {
    observer.disconnect();
    resizeObservers.delete(session);
  }
  try { item.socket.close(); } catch (_) {}
  try { item.term.dispose(); } catch (_) {}
}

function dismissTerminalConnectionToasts(session) {
  for (const node of document.querySelectorAll('.toast[data-toast-kind="terminal-connection"]')) {
    if (node.dataset.toastSession !== session) continue;
    removeAttentionAlert(Number(node.dataset.alertId || 0));
  }
}

function showTerminalConnectionToast(session, text, countdownMs = toastDurationMs) {
  dismissTerminalConnectionToasts(session);
  const node = showToast(
    `YOLOmux - ${serverHostname}: ${sessionLabel(session)} terminal`,
    text,
    {
      container: displayToastContainer(session),
      countdownMs,
      onClick: () => selectSession(session),
    },
  );
  if (node) {
    node.dataset.toastSession = session;
    node.dataset.toastKind = 'terminal-connection';
  }
}

function scheduleTerminalReconnect(session, item) {
  if (item.manualClose || terminals.get(session) !== item || !activeSessions.includes(session)) return;
  const delay = Math.min(8000, 1000 * 2 ** item.reconnectAttempt);
  item.reconnectAttempt += 1;
  if (item.reconnectTimer) clearTimeout(item.reconnectTimer);
  statusErr(`${esc(sessionLabel(session))} disconnected; reconnecting in ${Math.round(delay / 1000)}s`);
  showTerminalConnectionToast(session, `Disconnected. Reconnecting in ${Math.round(delay / 1000)}s.`, delay);
  item.reconnectTimer = setTimeout(() => {
    if (item.manualClose || terminals.get(session) !== item || !activeSessions.includes(session)) return;
    item.reconnectTimer = null;
    connectTerminalSocket(session, item);
  }, delay);
}

// A tmux session that is absent from the live roster has been killed (vs a transient disconnect).
function sessionConfirmedGone(session, order) {
  return isTmuxSession(session) && Array.isArray(order) && !order.includes(session);
}

// Tear down a dead session's UI immediately (terminal, panel, metadata) — mirrors killSession's
// cleanup without the confirm/POST, for sessions that ended outside this client.
function pruneDeadSession(session) {
  const previousActive = activeSessions.slice();
  stopSessionUi(session);
  autoApproveStates.delete(session);
  if (sessions.includes(session)) updateSessionList(sessions.filter(item => item !== session));
  updateDocumentTitle();
  renderSessionButtons();
  renderPanels(previousActive);
  renderPaneTabStrips();
  renderAutoApproveButtons();
  statusOk(`${esc(sessionLabel(session))} ended`);
}

// On a terminal WebSocket close, confirm via the roster whether the session is actually gone. If so,
// prune it from the UI immediately instead of reconnecting and waiting for the next poll to notice.
async function confirmSessionGoneOrReconnect(session, item) {
  if (item.manualClose || terminals.get(session) !== item) return;
  // DOIT.6 #86: one in-flight confirmation per terminal. A flapping WS could otherwise run several
  // concurrent confirmations, each scheduling a reconnect and double-incrementing reconnectAttempt
  // (distorting the backoff).
  if (item.confirmingGone) return;
  item.confirmingGone = true;
  try {
    let order = null;
    try {
      const response = await apiFetch('/api/auto-approve');
      const payload = await response.json();
      if (Array.isArray(payload.session_order)) order = payload.session_order;
    } catch (_) {}
    if (item.manualClose || terminals.get(session) !== item) return;
    if (sessionConfirmedGone(session, order)) {
      pruneDeadSession(session);
      return;
    }
    scheduleTerminalReconnect(session, item);
  } finally {
    item.confirmingGone = false;
  }
}

function estimateTerminalSize(container, term = null) {
  const content = terminalContentSize(container);
  const measured = term?._core?._renderService?._renderer?.dimensions?.css?.cell
    || term?._core?._renderService?.dimensions?.css?.cell
    || null;
  if (measured?.width && measured?.height) {
    return {
      cols: Math.max(40, Math.floor((content.width - 2) / measured.width)),
      rows: Math.max(10, Math.floor((content.height - terminalFitBottomReservePx) / measured.height)),
    };
  }
  const probe = document.createElement('span');
  probe.textContent = 'W';
  probe.style.position = 'absolute';
  probe.style.visibility = 'hidden';
  probe.style.font = '13px ui-monospace, SFMono-Regular, Menlo, Consolas, "Liberation Mono", monospace';
  document.body.appendChild(probe);
  const rect = probe.getBoundingClientRect();
  probe.remove();
  const charWidth = Math.max(7, rect.width || 8);
  const charHeight = Math.max(14, rect.height || 16);
  return {
    cols: Math.max(40, Math.floor((content.width - 2) / charWidth)),
    rows: Math.max(10, Math.floor((content.height - terminalFitBottomReservePx) / charHeight)),
  };
}

function terminalContentSize(container) {
  const style = getComputedStyle(container);
  const horizontalPadding = px(style.paddingLeft) + px(style.paddingRight);
  const verticalPadding = px(style.paddingTop) + px(style.paddingBottom);
  return {
    width: Math.max(0, container.clientWidth - horizontalPadding),
    height: Math.max(0, container.clientHeight - verticalPadding),
  };
}

function px(value) {
  const number = Number.parseFloat(value);
  return Number.isFinite(number) ? number : 0;
}

function slotSide(slot) {
  return slotColumn(slot);
}

function slotForItem(item, slots = layoutSlots) {
  return layoutSlotKeys(slots).find(side => paneTabs(side, slots).includes(item)) || null;
}

function slotForSession(session) {
  return slotForItem(session);
}

function slotForDropEvent(event) {
  const rect = grid.getBoundingClientRect();
  return event.clientX < rect.left + rect.width / 2 ? 'left' : 'right';
}

function layoutBoundaryDropBandPx(size) {
  const scaled = Math.max(0, Number(size) || 0) * layoutBoundaryDropFraction;
  return Math.min(layoutBoundaryDropMaxPx, Math.max(layoutBoundaryDropMinPx, scaled));
}

function rootBoundaryDropZoneForEvent(event, rect) {
  if (!rect.width || !rect.height) return null;
  const insideX = event.clientX >= rect.left && event.clientX <= rect.right;
  const insideY = event.clientY >= rect.top && event.clientY <= rect.bottom;
  if (!insideX || !insideY) return null;
  const xBand = layoutBoundaryDropBandPx(rect.width);
  const yBand = layoutBoundaryDropBandPx(rect.height);
  const candidates = [
    {zone: 'left', distance: Math.abs(event.clientX - rect.left), active: event.clientX <= rect.left + xBand},
    {zone: 'right', distance: Math.abs(rect.right - event.clientX), active: event.clientX >= rect.right - xBand},
    {zone: 'top', distance: Math.abs(event.clientY - rect.top), active: event.clientY <= rect.top + yBand},
    {zone: 'bottom', distance: Math.abs(rect.bottom - event.clientY), active: event.clientY >= rect.bottom - yBand},
  ].filter(candidate => candidate.active);
  candidates.sort((left, right) => left.distance - right.distance);
  return candidates[0]?.zone || null;
}

function rootBoundaryDropIntentForEvent(event) {
  const targetRect = grid.getBoundingClientRect();
  const zone = rootBoundaryDropZoneForEvent(event, targetRect);
  if (!zone) return null;
  return {targetSlot: slotForDropEvent(event), zone, previewNode: grid, targetRect, boundary: 'root'};
}

function gutterDropZoneForEvent(event, node, rect) {
  if (!node?.children?.length || !rect.width || !rect.height) return null;
  if (node.split === 'column') return event.clientY < rect.top + rect.height / 2 ? 'top' : 'bottom';
  return event.clientX < rect.left + rect.width / 2 ? 'left' : 'right';
}

function gutterDropIntentForEvent(event) {
  const resizer = event.target?.closest?.('.layout-resizer');
  const splitPath = resizer?.dataset?.splitPath;
  if (!resizer || splitPath === undefined) return null;
  const targetRect = resizer.getBoundingClientRect();
  const node = layoutNodeAtPath(splitPath);
  const zone = gutterDropZoneForEvent(event, node, targetRect);
  if (!zone) return null;
  return {targetSlot: slotForDropEvent(event), zone, previewNode: grid, targetRect, boundary: 'gutter', splitPath};
}

function dropZoneForRect(event, rect) {
  if (!rect.width || !rect.height) return 'middle';
  const x = (event.clientX - rect.left) / rect.width;
  const y = (event.clientY - rect.top) / rect.height;
  if (y < 0.24) return rect.height / 2 >= minSplitPaneHeightPx ? 'top' : 'middle';
  if (y > 0.76) return rect.height / 2 >= minSplitPaneHeightPx ? 'bottom' : 'middle';
  if (x < 0.24) return rect.width / 2 >= minSplitPaneWidthPx ? 'left' : 'middle';
  if (x > 0.76) return rect.width / 2 >= minSplitPaneWidthPx ? 'right' : 'middle';
  return 'middle';
}

function dropIntentForEvent(event, options = {}) {
  if (options.allowBoundary === true) {
    const rootIntent = rootBoundaryDropIntentForEvent(event);
    if (rootIntent) return rootIntent;
    const gutterIntent = gutterDropIntentForEvent(event);
    if (gutterIntent) return gutterIntent;
  }
  const slotNode = event.target?.closest?.('.drop-slot');
  if (slotNode?.dataset.slot) {
    const targetSlot = slotNode.dataset.slot;
    const targetRect = slotNode.getBoundingClientRect();
    return {targetSlot, zone: dropZoneForRect(event, targetRect), previewNode: slotNode, targetRect};
  }
  return {targetSlot: slotForDropEvent(event), zone: 'middle', previewNode: null, targetRect: grid.getBoundingClientRect()};
}

function slotIsFileExplorerPane(slot) {
  return isFileExplorerItem(activeItemForSide(slot));
}

function slotIsChangesPane(slot) {
  return isChangesItem(activeItemForSide(slot));
}

function dropIntentInlineSize(intent) {
  if (!intent || typeof intent === 'string') return 0;
  const rect = intent.targetRect || intent.previewNode?.getBoundingClientRect?.();
  return Math.max(0, Number(rect?.width) || 0);
}

function itemCanSplitSinglePurposePane(item, intent) {
  const zone = typeof intent === 'string' ? intent : intent?.zone;
  if (zone !== 'top' && zone !== 'bottom') return false;
  if (isFileExplorerItem(item) || isChangesItem(item)) return false;
  const inlineSize = dropIntentInlineSize(intent);
  return !inlineSize || inlineSize >= minWidthForLayoutItem(item);
}

function dropIntentAllowsSession(session, intent) {
  if (!isLayoutItem(session)) return false;
  if ((intent?.boundary === 'root' || intent?.boundary === 'gutter') && layoutSplitZone(intent.zone)) return true;
  if (!intent?.targetSlot) return false;
  if (slotIsFileExplorerPane(intent.targetSlot) || slotIsChangesPane(intent.targetSlot)) {
    return itemCanSplitSinglePurposePane(session, intent);
  }
  return true;
}

function clearDropPreview() {
  const classes = ['drag-over', 'tab-drag-over', 'tab-drop-preview', 'drop-preview', 'drop-preview-top', 'drop-preview-bottom', 'drop-preview-left', 'drop-preview-right', 'drop-preview-middle', 'drop-preview-root', 'drop-preview-gutter'];
  const nodes = new Set([grid]);
  for (const className of classes) {
    grid.querySelectorAll(`.${className}`).forEach(node => nodes.add(node));
  }
  nodes.forEach(node => {
    node.classList.remove(...classes);
    node.style?.removeProperty('--tab-drop-x');
    node.style?.removeProperty('--tab-drop-y');
    node.style?.removeProperty('--tab-drop-height');
    node.style?.removeProperty('--drop-preview-left');
    node.style?.removeProperty('--drop-preview-top');
    node.style?.removeProperty('--drop-preview-width');
    node.style?.removeProperty('--drop-preview-height');
    if (node.dataset) delete node.dataset.dropLabel;
  });
}

function applyGutterDropPreviewGeometry(node, intent) {
  if (intent?.boundary !== 'gutter' || node !== grid) return;
  const gridRect = grid.getBoundingClientRect();
  const targetRect = intent.targetRect || gridRect;
  const isHorizontalBand = intent.zone === 'left' || intent.zone === 'right';
  const inlineSize = isHorizontalBand ? gridRect.width : gridRect.height;
  const bandSize = Math.max(layoutBoundaryDropMinPx * 2, Math.min(layoutBoundaryDropMaxPx * 3, inlineSize * 0.24));
  if (isHorizontalBand) {
    const center = targetRect.left + targetRect.width / 2 - gridRect.left;
    const left = Math.max(6, Math.min(gridRect.width - bandSize - 6, center - bandSize / 2));
    node.style.setProperty('--drop-preview-left', `${Math.round(left)}px`);
    node.style.setProperty('--drop-preview-top', '6px');
    node.style.setProperty('--drop-preview-width', `${Math.round(bandSize)}px`);
    node.style.setProperty('--drop-preview-height', 'calc(100% - 12px)');
  } else {
    const center = targetRect.top + targetRect.height / 2 - gridRect.top;
    const top = Math.max(6, Math.min(gridRect.height - bandSize - 6, center - bandSize / 2));
    node.style.setProperty('--drop-preview-left', '6px');
    node.style.setProperty('--drop-preview-top', `${Math.round(top)}px`);
    node.style.setProperty('--drop-preview-width', 'calc(100% - 12px)');
    node.style.setProperty('--drop-preview-height', `${Math.round(bandSize)}px`);
  }
}

function layoutNodeScreenRect(layoutNode) {
  const rects = layoutLeafSlots(layoutNode)
    .map(slot => layoutColumnNode(slot)?.getBoundingClientRect?.())
    .filter(rect => rect && rect.width > 0 && rect.height > 0);
  if (!rects.length) return null;
  const left = Math.min(...rects.map(rect => rect.left));
  const top = Math.min(...rects.map(rect => rect.top));
  const right = Math.max(...rects.map(rect => rect.right));
  const bottom = Math.max(...rects.map(rect => rect.bottom));
  return {left, top, right, bottom, width: right - left, height: bottom - top};
}

function applyDockedFileExplorerBoundaryPreviewGeometry(node, intent) {
  if (intent?.boundary !== 'root' || node !== grid) return;
  if (intent.zone !== 'top' && intent.zone !== 'bottom') return;
  const root = layoutSlots?.[layoutTreeKey];
  const docked = dockedFileExplorerRootSplit(root, layoutSlots);
  if (!docked) return;
  const gridRect = grid.getBoundingClientRect();
  const contentRect = layoutNodeScreenRect(root?.children?.[docked.contentIndex]);
  if (!gridRect || !contentRect) return;
  node.style.setProperty('--drop-preview-left', `${Math.round(contentRect.left - gridRect.left + 6)}px`);
  node.style.setProperty('--drop-preview-width', `${Math.round(Math.max(0, contentRect.width - 12))}px`);
}

function showDropPreview(intent) {
  clearDropPreview();
  const node = intent?.boundary ? grid : intent?.previewNode;
  if (!node) return;
  const zone = intent.zone || 'middle';
  node.classList.add('drag-over', 'drop-preview', `drop-preview-${zone}`);
  if (intent.boundary) node.classList.add(`drop-preview-${intent.boundary}`);
  node.dataset.dropLabel = intent.boundary === 'root'
    ? `full ${zone}`
    : intent.boundary === 'gutter'
      ? 'full span'
      : zone === 'middle'
        ? 'take over'
        : zone;
  applyGutterDropPreviewGeometry(node, intent);
  applyDockedFileExplorerBoundaryPreviewGeometry(node, intent);
}

function dropSessionAtEvent(event) {
  const filePayload = fileDragPayload(event);
  if (filePayload?.path) {
    event.preventDefault();
    event.stopPropagation();
    const intent = dropIntentForEvent(event, {allowBoundary: false});
    clearDropPreview();
    if (!intent?.targetSlot) return;
    if ((slotIsFileExplorerPane(intent.targetSlot) || slotIsChangesPane(intent.targetSlot)) && intent.zone === 'middle') return;
    const zone = slotIsFileExplorerPane(intent.targetSlot) && intent.zone === 'middle' ? 'right' : intent.zone;
    openDraggedFilesInEditor(filePayload, {targetSlot: intent.targetSlot, targetZone: zone});
    return;
  }
  const payload = dragPayload(event);
  if (!payload?.session) return;
  if (event.target?.closest?.('.panel-head')) {
    event.preventDefault();
    event.stopPropagation();
    clearDropPreview();
    return;
  }
  event.preventDefault();
  event.stopPropagation();
  const intent = dropIntentForEvent(event, {allowBoundary: true});
  clearDropPreview();
  if (!dropIntentAllowsSession(payload.session, intent)) return;
  dropSessionWithIntent(payload.session, intent, payload.sourceSlot || slotForSession(payload.session));
}

function handleDropDragOver(event) {
  const filePayload = fileDragPayload(event);
  if (filePayload?.path) {
    const intent = dropIntentForEvent(event, {allowBoundary: false});
    if ((slotIsFileExplorerPane(intent.targetSlot) || slotIsChangesPane(intent.targetSlot)) && intent.zone === 'middle') {
      event.preventDefault();
      event.stopPropagation();
      event.dataTransfer.dropEffect = 'none';
      clearDropPreview();
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    event.dataTransfer.dropEffect = 'copy';
    showDropPreview(intent);
    return;
  }
  const payload = dragPayload(event);
  if (!payload?.session) return;
  if (event.target?.closest?.('.panel-head')) {
    event.preventDefault();
    event.stopPropagation();
    event.dataTransfer.dropEffect = 'none';
    clearDropPreview();
    return;
  }
  const intent = dropIntentForEvent(event, {allowBoundary: true});
  event.preventDefault();
  event.stopPropagation();
  if (!dropIntentAllowsSession(payload.session, intent)) {
    event.dataTransfer.dropEffect = 'none';
    clearDropPreview();
    return;
  }
  event.dataTransfer.dropEffect = 'move';
  showDropPreview(intent);
}

function handleDropDragLeave(event) {
  const current = event.currentTarget;
  if (current?.contains(event.relatedTarget)) return;
  clearDropPreview();
}
function renderPanels(previousActive = [], options = {}) {
  // DOIT.6 #114: a full panel re-render pools every panel and clears the grid, which detaches
  // the node being dragged and aborts the native HTML5 drag. Defer the re-render until the drag
  // ends; endSessionDrag flushes pendingPanelsRender. Drops still render because endSessionDrag
  // clears dragSession before flushing.
  if (dragSession != null) { pendingPanelsRender = true; return; }
  movePanelsToPool();
  const activePaneCount = layoutSlotKeys().filter(side => activeItemForSide(side) || paneIsPlaceholder(side)).length;
  grid.className = `grid ${activePaneCount === 1 ? 'full' : ''} ${activePaneCount === 0 ? 'empty' : ''}`.trim();
  grid.innerHTML = '';
  const tree = layoutSlots[layoutTreeKey];
  if (tree) grid.appendChild(renderLayoutRoot(tree));

  bindDropTargets();
  syncPanelVisibility(previousActive);
  renderAutoApproveButtons();
  if (options.prune === false) {
    if (responsiveLayoutPruneTimer) {
      clearTimeout(responsiveLayoutPruneTimer);
      responsiveLayoutPruneTimer = null;
    }
  } else {
    scheduleResponsiveLayoutPrune();
  }
}

function movePanelsToPool() {
  for (const [item, panel] of panelNodes.entries()) {
    if (isFileEditorItem(item)) captureFileEditorPanelViewState(item, panel);
    panel.classList.remove('active-pane');
    panel.dataset.slot = '';
    panelPool.appendChild(panel);
  }
}

// DOIT.9 S2: the registered item for a mounted panel node (reverse lookup of panelNodes).
function panelItemForNode(node) {
  if (!node) return null;
  for (const [item, panel] of panelNodes.entries()) {
    if (panel === node) return item;
  }
  return null;
}

// DOIT.9 S2: move ONE displaced panel back to the pool (preserving editor state), like movePanelsToPool
// does for all. An empty-pane placeholder (not in panelNodes) is just dropped.
function poolDisplacedPanel(node) {
  const item = panelItemForNode(node);
  if (item == null) return;
  if (isFileEditorItem(item)) captureFileEditorPanelViewState(item, node);
  node.classList.remove('active-pane');
  node.dataset.slot = '';
  panelPool.appendChild(node);
}

// DOIT.9 S2: for a SAME-SHAPE layout change, swap only the slots whose ACTIVE item changed — no
// grid.innerHTML='' / topbar teardown, no detach/reattach of unrelated panes. A pure reorder touches
// zero panels (active unchanged) and only reconciles the tab strip via updatePanelSlot.
function syncActivePanelsInPlace() {
  for (const dropSlot of grid.querySelectorAll('.drop-slot[data-slot]')) {
    const slot = dropSlot.dataset.slot;
    const item = activeItemForSide(slot);
    const mounted = dropSlot.querySelector(':scope > .panel');
    if (!item) {
      if (!mounted || !mounted.classList.contains('empty-pane-panel')) {
        poolDisplacedPanel(mounted);
        dropSlot.replaceChildren(renderEmptyPane(slot));
      }
      continue;
    }
    const desired = getOrCreatePanel(item);
    if (mounted === desired) {
      updatePanelSlot(desired, item, slot);
      continue;
    }
    poolDisplacedPanel(mounted);
    dropSlot.replaceChildren(desired);
    updatePanelSlot(desired, item, slot);
  }
}

function bindDropTargets() {
  grid.ondragover = handleDropDragOver;
  grid.ondragleave = handleDropDragLeave;
  grid.ondrop = dropSessionAtEvent;
  grid.querySelectorAll('[data-side], [data-slot]').forEach(node => {
    node.addEventListener('dragover', handleDropDragOver);
    node.addEventListener('dragleave', handleDropDragLeave);
    node.addEventListener('drop', dropSessionAtEvent);
  });
}

function renderLayoutRoot(node) {
  const section = document.createElement('section');
  section.className = 'layout-root';
  section.appendChild(renderLayoutNode(node, ''));
  return section;
}

function renderLayoutNode(node, path) {
  if (node.slot) return renderLayoutColumn(node.slot);
  const section = document.createElement('section');
  section.className = `layout-split ${node.split === 'column' ? 'split-column' : 'split-row'}`;
  section.dataset.splitPath = path;
  const children = node.children || [];
  const first = renderLayoutNode(children[0], layoutChildPath(path, 0));
  const second = renderLayoutNode(children[1], layoutChildPath(path, 1));
  const handle = document.createElement('div');
  handle.className = `layout-resizer ${node.split === 'column' ? 'resizer-column' : 'resizer-row'}`;
  handle.role = 'separator';
  handle.tabIndex = 0;
  handle.dataset.splitPath = path;
  handle.setAttribute('aria-orientation', node.split === 'column' ? 'horizontal' : 'vertical');
  handle.setAttribute('aria-label', t('pane.resize'));
  section.append(first, handle, second);
  applySplitPercentToSection(section, node.pct);
  bindLayoutResizer(handle, section, path);
  return section;
}

function layoutChildPath(path, index) {
  return path ? `${path}.${index}` : String(index);
}

function layoutNodeAtPath(path, root = layoutSlots[layoutTreeKey]) {
  let node = root;
  if (!path) return node;
  for (const part of String(path).split('.')) {
    const index = Number(part);
    if (!node?.children || !Number.isInteger(index)) return null;
    node = node.children[index];
  }
  return node || null;
}

function applySplitPercentToSection(section, pct) {
  const first = section.children[0];
  const second = section.children[2];
  if (!first || !second) return;
  const value = splitPercent(pct);
  first.style.flex = `0 1 ${value}%`;
  second.style.flex = `1 1 ${100 - value}%`;
  const handle = section.children[1];
  if (handle?.style) handle.style.setProperty('--split-percent', `${value}%`);
}

function bindLayoutResizer(handle, section, path) {
  handle.addEventListener('pointerdown', event => {
    const node = layoutNodeAtPath(path);
    if (!node || !node.children) return;
    event.preventDefault();
    event.stopPropagation();
    layoutResizeState = {section, path, pointerId: event.pointerId};
    handle.setPointerCapture?.(event.pointerId);
    document.body.classList.add('layout-resizing', node.split === 'column' ? 'layout-resizing-column' : 'layout-resizing-row');
    window.addEventListener('pointermove', onLayoutResizeMove, {capture: true});
    window.addEventListener('pointerup', onLayoutResizeEnd, {capture: true});
    onLayoutResizeMove(event);
  });
}

function onLayoutResizeMove(event) {
  const state = layoutResizeState;
  if (!state) return;
  event.preventDefault();
  const node = layoutNodeAtPath(state.path);
  if (!node || !node.children) return;
  const pct = splitPercentForPointer(state.section, node, event);
  node.pct = pct;
  applySplitPercentToSection(state.section, pct);
  for (const session of activeSessions.filter(isTmuxSession)) scheduleFit(session);
}

function onLayoutResizeEnd(event) {
  if (!layoutResizeState) return;
  event.preventDefault();
  const state = layoutResizeState;
  const handle = state.section.querySelector(`:scope > .layout-resizer[data-split-path="${cssEscape(state.path)}"]`);
  try { handle?.releasePointerCapture?.(state.pointerId); } catch (_) {}
  layoutResizeState = null;
  document.body.classList.remove('layout-resizing', 'layout-resizing-column', 'layout-resizing-row');
  window.removeEventListener('pointermove', onLayoutResizeMove, {capture: true});
  window.removeEventListener('pointerup', onLayoutResizeEnd, {capture: true});
  updateActiveSessionParam();
  scheduleResponsiveLayoutPrune();
}

function splitPercentForPointer(section, nodeOrDirection, event) {
  const direction = typeof nodeOrDirection === 'string' ? nodeOrDirection : nodeOrDirection?.split;
  const rect = section.getBoundingClientRect();
  const size = direction === 'column' ? rect.height : rect.width;
  if (!size) return defaultSplitPercent;
  const offset = direction === 'column' ? event.clientY - rect.top : event.clientX - rect.left;
  const raw = (offset / size) * 100;
  const children = Array.isArray(nodeOrDirection?.children) ? nodeOrDirection.children : null;
  const minFirst = children
    ? (direction === 'column' ? layoutNodeMinHeight(children[0]) : layoutNodeMinWidth(children[0]))
    : (direction === 'column' ? minSplitPaneHeightPx : minSplitPaneWidthPx);
  const minSecond = children
    ? (direction === 'column' ? layoutNodeMinHeight(children[1]) : layoutNodeMinWidth(children[1]))
    : (direction === 'column' ? minSplitPaneHeightPx : minSplitPaneWidthPx);
  if (size >= minFirst + minSecond) {
    const minFirstPct = (minFirst / size) * 100;
    const maxFirstPct = 100 - (minSecond / size) * 100;
    return Math.min(maxFirstPct, Math.max(minFirstPct, raw));
  }
  return splitPercent(raw);
}

function scheduleResponsiveLayoutPrune() {
  if (layoutResizeState || responsiveLayoutPruneTimer) return;
  responsiveLayoutPruneTimer = setTimeout(() => {
    responsiveLayoutPruneTimer = null;
    requestAnimationFrame(pruneSmallLayoutSlots);
  }, 80);
}

function pruneSmallLayoutSlots() {
  if (layoutResizeState || layoutVisiblePaneCount() <= 1) return;
  const candidate = smallLayoutSlotCandidate();
  if (!candidate) return;
  const moved = paneTabs(candidate.slot);
  applyLayoutSlots(layoutWithoutSlot(candidate.slot), {
    message: moved.length ? `${moved.map(itemLabel).join(', ')} hidden from layout: not enough room` : '',
  });
}

function minWidthForLayoutItem(item) {
  const type = tabTypeForItem(item);
  if (type?.minWidth) return type.minWidth(item);
  return minSplitPaneWidthPx;
}

function minWidthForLayoutSlot(slot, slots = layoutSlots) {
  return minWidthForLayoutItem(activeItemForSide(slot, slots));
}

function layoutVisiblePaneCount(slots = layoutSlots) {
  return layoutSlotKeys(slots).filter(slot => paneHasLayoutContent(slot, slots)).length;
}

function layoutNodeMinWidth(node, slots = layoutSlots) {
  if (!node) return minSplitPaneWidthPx;
  if (node.slot) return paneHasLayoutContent(node.slot, slots) ? minWidthForLayoutSlot(node.slot, slots) : minSplitPaneWidthPx;
  const children = node.children || [];
  if (node.split === 'column') return Math.max(...children.map(child => layoutNodeMinWidth(child, slots)), minSplitPaneWidthPx);
  return children.reduce((sum, child) => sum + layoutNodeMinWidth(child, slots), 0);
}

function layoutNodeMinHeight(node, slots = layoutSlots) {
  if (!node) return minSplitPaneHeightPx;
  if (node.slot) return paneHasLayoutContent(node.slot, slots) ? minSplitPaneHeightPx : minSplitPaneHeightPx;
  const children = node.children || [];
  if (node.split === 'column') return children.reduce((sum, child) => sum + layoutNodeMinHeight(child, slots), 0);
  return Math.max(...children.map(child => layoutNodeMinHeight(child, slots)), minSplitPaneHeightPx);
}

function prunePriorityForLayoutSlot(slot) {
  const item = activeItemForSide(slot);
  const type = tabTypeForItem(item);
  if (type?.prunePriority) return type.prunePriority(item);
  return 2;
}

function slotCanAutoPrune(slot) {
  return !isFileExplorerItem(activeItemForSide(slot));
}

function smallLayoutSlotCandidate() {
  let candidate = null;
  let virtualCandidate = null;
  for (const column of grid.querySelectorAll('.layout-column[data-slot]')) {
    const slot = column.dataset.slot;
    if (!slot || !paneTabs(slot).length) continue;
    if (!slotCanAutoPrune(slot)) continue;
    const rect = column.getBoundingClientRect();
    const area = Math.max(0, rect.width) * Math.max(0, rect.height);
    const priority = prunePriorityForLayoutSlot(slot);
    const item = activeItemForSide(slot);
    if (isVirtualItem(item) && (!virtualCandidate || area < virtualCandidate.area)) {
      virtualCandidate = {slot, area, priority};
    }
    const tooSmall = rect.width < minWidthForLayoutSlot(slot) || rect.height < minSplitPaneHeightPx;
    if (!tooSmall) continue;
    const nextCandidate = {slot, area, priority};
    if (!candidate || priority < candidate.priority || (priority === candidate.priority && area < candidate.area)) {
      candidate = nextCandidate;
    }
  }
  if (candidate && prunePriorityForLayoutSlot(candidate.slot) >= 2 && virtualCandidate) return virtualCandidate;
  return candidate;
}

function renderLayoutColumn(side) {
  const column = document.createElement('section');
  const session = activeItemForSide(side);
  column.className = 'layout-column';
  if (isFileExplorerItem(session)) column.classList.add('file-explorer-column');
  if (isPreferencesItem(session)) column.classList.add('preferences-column');
  if (isChangesItem(session)) column.classList.add('changes-column');
  if (isFileEditorItem(session)) column.classList.add('file-editor-column');
  if (!session) column.classList.add('empty-pane-column');
  column.dataset.slot = side;
  column.dataset.side = slotSide(side);
  column.appendChild(renderDropSlot(side, session));
  return column;
}

function renderDropSlot(slot, session) {
  const node = document.createElement('section');
  node.className = 'drop-slot';
  node.dataset.slot = slot;
  node.dataset.side = slotSide(slot);
  if (!session) {
    node.appendChild(renderEmptyPane(slot));
    return node;
  }
  const panel = getOrCreatePanel(session);
  updatePanelSlot(panel, session, slot);
  node.appendChild(panel);
  return node;
}

function renderEmptyPane(slot) {
  const panel = document.createElement('article');
  panel.className = 'panel empty-pane-panel';
  panel.dataset.slot = slot;
  panel.setAttribute('aria-label', t('pane.empty'));
  panel.appendChild(document.createElement('div'));
  panel.children[0].className = 'empty-pane-fill';
  return panel;
}

function renderPaneTabStrips() {
  // DOIT.6 #30: do not rebuild tab DOM while a tab is being dragged — replacing the dragged node
  // aborts the native drag. Defer to the endSessionDrag flush.
  if (dragSession != null) { pendingTabStripRender = true; return; }
  for (const side of layoutSlotKeys()) {
    const session = activeItemForSide(side);
    if (!session) continue;
    const panel = panelNodes.get(session);
    if (panel) {
      updatePaneExpandButton(panel, session);
      updatePaneTabStrip(panel, side);
    }
  }
}

function updatePaneTabStrip(panel, side) {
  const strip = panel.querySelector('.pane-tabs');
  if (!strip) return;
  const stack = paneTabs(side);
  strip.dataset.side = side;
  if (isFileExplorerItem(activeItemForSide(side))) {
    strip.hidden = true;
    strip.replaceChildren();
    return;
  }
  strip.hidden = false;
  const restorePopoverItem = paneTabPopoverItemToRestore(strip);
  const activeItem = activeItemForSide(side);
  const items = stack.slice();
  if (activeItem && !items.includes(activeItem)) items.push(activeItem);
  reconcilePaneTabChildren(strip, side, items);
  bindPaneTabStrip(strip, side);
  restorePaneTabPopover(strip, restorePopoverItem);
  scheduleTabStripOverflowCheck(strip);
}

function reconcilePaneTabChildren(strip, side, items) {
  const existingByItem = new Map(Array.from(strip.querySelectorAll(':scope > .pane-tab')).map(tab => [tab.dataset.paneTab || '', tab]));
  const nextNodes = [];
  for (const item of items) {
    const fresh = createPaneTab(side, item);
    const existing = existingByItem.get(item);
    if (existing && paneTabShouldPreserve(existing)) {
      syncPreservedPaneTab(existing, fresh);
      nextNodes.push(existing);
    } else {
      nextNodes.push(fresh);
    }
    existingByItem.delete(item);
  }
  for (const leftover of existingByItem.values()) leftover.remove();
  reconcileChildNodes(strip, nextNodes, {lockedNodes: nextNodes.filter(paneTabShouldPreserve)});
}

function paneTabShouldPreserve(tab) {
  const popover = tab.querySelector(':scope > .session-popover');
  return Boolean(popover && (popoverLifecycleActive(tab, popover) || popoverStillActive(tab, popover)));
}

function classNameSet(value) {
  return new Set(String(value || '').split(/\s+/).filter(Boolean));
}

function syncClassListPreserving(node, freshClassName, preservedNames = []) {
  const current = classNameSet(node.className);
  const next = classNameSet(freshClassName);
  for (const name of preservedNames) {
    if (current.has(name) || node.classList?.contains?.(name)) next.add(name);
  }
  for (const name of current) {
    if (!next.has(name)) node.classList?.remove?.(name);
  }
  for (const name of next) {
    if (!current.has(name)) node.classList?.add?.(name);
  }
  // Test fakes do not keep className and classList synchronized; browsers do.
  if (!(globalThis.DOMTokenList && node.classList instanceof globalThis.DOMTokenList)) {
    node.className = Array.from(next).join(' ');
  }
}

function syncPreservedPaneTab(tab, fresh) {
  const hoverState = tab.dataset.popoverHoverState || '';
  syncClassListPreserving(tab, fresh.className, ['popover-open', 'dragging']);
  tab.role = fresh.role;
  tab.tabIndex = fresh.tabIndex;
  tab.draggable = fresh.draggable;
  tab.dataset.paneTab = fresh.dataset.paneTab;
  if (hoverState) tab.dataset.popoverHoverState = hoverState;
  else delete tab.dataset.popoverHoverState;
  const label = fresh.getAttribute('aria-label');
  if (label) tab.setAttribute('aria-label', label);
  else tab.removeAttribute('aria-label');
}

function paneTabPopoverItemToRestore(strip) {
  for (const tab of strip.querySelectorAll(':scope > .pane-tab')) {
    const popover = tab.querySelector(':scope > .session-popover');
    if (popover && (popoverLifecycleActive(tab, popover) || popoverStillActive(tab, popover))) return tab.dataset.paneTab || null;
  }
  return null;
}

function restorePaneTabPopover(strip, item) {
  if (!item) return;
  const tab = strip.querySelector(`:scope > .pane-tab[data-pane-tab="${cssEscape(item)}"]`);
  const popover = tab?.querySelector(':scope > .session-popover');
  if (!tab || !popover) return;
  if (tab.classList.contains('popover-open') && popoverLifecycleActive(tab, popover)) return;
  positionPaneTabPopover(tab);
  closeOtherSessionPopovers(tab);
  tab.classList.add('popover-open');
}

function createPaneTab(side, item) {
  const type = tabTypeForItem(item);
  const isFiles = type?.key === 'files';
  const isEditor = isFileEditorItem(item);
  const isVirtual = Boolean(type);
  const info = transcriptMeta.sessions?.[item];
  const auto = autoApproveStates.get(item)?.enabled === true && !isVirtual;
  const state = isVirtual ? null : sessionState(item, info);
  const agentKind = isVirtual ? '' : sessionAgentKind(item);
  const active = item === activeItemForSide(side);
  const tab = document.createElement('div');
  tab.role = 'button';
  tab.tabIndex = 0;
  const virtualClass = type?.className?.(item) || '';
  const missingFileClass = isEditor && openFileIsMissing(fileItemPath(item)) ? 'file-missing' : '';
  tab.className = `pane-tab ${virtualClass} ${missingFileClass} ${active ? 'active' : ''}`;
  applySessionStateClasses(tab, state);
  tab.draggable = true;
  tab.dataset.paneTab = item;
  if (type?.rowHtml) tab.innerHTML = type.rowHtml(item);
  else tab.innerHTML = tmuxPaneTabHtml(item, info, state, auto);
  if (!isFiles) {
    const closeTitle = isEditor ? `Close ${itemLabel(item)}` : `hide ${itemLabel(item)} from layout`;
    const closeLabel = isEditor ? `Close ${itemLabel(item)}` : `Hide ${itemLabel(item)} from layout`;
    const controlKind = isEditor ? 'close' : 'minimize';
    tab.insertAdjacentHTML('beforeend', `<button type="button" class="pane-tab-close ${platformWindowControlClass(controlKind)}" data-pane-tab-close title="${esc(closeTitle)}" aria-label="${esc(closeLabel)}"></button>`);
  }
  if (isEditor) {
    tab.insertAdjacentHTML('beforeend', filePopoverHtml(item));
    bindFilePopoverActions(tab);
    bindPaneTabPopover(tab, item);
  } else if (!isVirtual) {
    tab.insertAdjacentHTML('beforeend', sessionPopoverHtml(item, info, agentKind, auto, state));
    bindPaneTabPopover(tab, item);
  }
  tab.setAttribute('aria-label', type ? itemLabel(item) : isEditor ? `${itemLabel(item)}${missingFileClass ? ' missing on disk' : ''}` : `${sessionLabel(item)} ${sessionWorkDescription(item, info, 140)}`.trim());
  tab.addEventListener('pointerdown', event => {
    if (event.target.closest('[data-pane-tab-close]')) {
      event.stopPropagation();
      return;
    }
    const autoTarget = event.target.closest('[data-auto-session]');
    if (!autoTarget) return;
    event.preventDefault();
    event.stopPropagation();
    if (item === activeItemForSide(side)) setFocusedPanelItem(item);
  });
  tab.addEventListener('click', async event => {
    if (event.target.closest('[data-pane-tab-close]')) {
      event.preventDefault();
      event.stopPropagation();
      if (isEditor) closeFileTab(fileItemPath(item), {item});
      else removeSessionFromLayout(item);
      return;
    }
    const autoTarget = event.target.closest('[data-auto-session]');
    if (autoTarget) {
      event.preventDefault();
      event.stopPropagation();
      const shouldRefocus = item === activeItemForSide(side);
      await toggleAutoApprove(autoTarget.dataset.autoSession);
      if (shouldRefocus) focusPanel(item);
      return;
    }
  });
  tab.addEventListener('keydown', event => {
    if (!['Enter', ' '].includes(event.key)) return;
    event.preventDefault();
    activatePaneTab(side, item, {userInitiated: true});
  });
  bindTabActivation(tab, () => activatePaneTab(side, item, {userInitiated: true}), {
    stopPropagation: true,
    ignore: event => Boolean(event.target.closest('[data-auto-session], [data-pane-tab-close]')),
  });
  if (isEditor) {
    tab.addEventListener('dblclick', event => {
      if (event.target.closest('[data-pane-tab-close]')) return;
      event.preventDefault();
      event.stopPropagation();
      beginPaneTabRename(tab, item);
    });
  } else if (!isVirtual) {
    tab.addEventListener('dblclick', event => {
      if (event.target.closest('[data-auto-session], [data-pane-tab-close]')) return;
      event.preventDefault();
      event.stopPropagation();
      beginPaneTabRename(tab, item);
    });
    tab.addEventListener('contextmenu', event => {
      event.preventDefault();
      event.stopPropagation();
      showSessionContextMenu(item, event.clientX, event.clientY, {tab});
    });
  }
  tab.addEventListener('dragstart', event => {
    event.stopPropagation();
    startSessionDrag(event, item, side);
  });
  tab.addEventListener('dragend', endSessionDrag);
  return tab;
}

function beginPaneTabRename(tab, session) {
  if (isFileEditorItem(session)) {
    beginFileTabRename(tab, session);
    return;
  }
  if (isTmuxSession(session)) renameTmuxSession(session);
}

function beginFileTabRename(tab, item) {
  const path = fileItemPath(item);
  if (!path) return;
  const entry = {kind: 'file', name: basenameOf(path)};
  const row = document.querySelector(`.file-tree-row[data-path="${cssEscape(path)}"]`);
  if (row) {
    beginFileTreeRename(row, path, entry);
    return;
  }
  if (readOnlyMode) {
    statusErr('readonly access cannot rename files');
    return;
  }
  const currentName = basenameOf(path);
  const nextName = window.prompt(`Rename ${currentName}`, currentName);
  if (nextName === null) return;
  renameFileTreePath(path, entry, nextName);
}

function bindPaneTabPopover(tab, session) {
  const popover = tab.querySelector?.(':scope > .session-popover');
  if (!popover) return;
  bindDelayedSessionPopover(tab, popover, () => positionPaneTabPopover(tab));
}

function bindDelayedSessionPopover(anchor, popover, position) {
  createHoverPopover({
    anchor,
    popover,
    showDelay: () => (document.querySelector('.pane-tab.popover-open') ? tabPopoverFollowDelayMs : tabPopoverShowDelayMs),
    hideDelay: () => popoverHideDelayMs,
    canOpen: () => !appMenuIsOpen() && !topbar?.matches?.(':hover'),
    onQueue: position,
    position,
    closeOthers: () => closeOtherSessionPopovers(anchor),
  });
}

function positionPaneTabPopover(tab) {
  const rect = tab.getBoundingClientRect();
  const popover = tab.querySelector?.(':scope > .session-popover');
  const bridgeGap = 3;
  const edgeGap = popoverEdgeGapPx();
  const topbarBottom = Math.ceil(topbar?.getBoundingClientRect?.().bottom || rootCssLengthPx('--topbar-height') || 0);
  const bounds = viewportBounds(edgeGap);
  const maxInline = Math.max(0, bounds.right - bounds.left);
  // #45: when the live popover width measures 0 (e.g. before first paint), fall back to the popover's
  // CSS inline size (capped to the viewport) — NOT the tiny tab width. Over-estimating only pulls a
  // near-right-edge popover further left; clamping to the tab width let a wide needs-input popover
  // overflow and clip off the top-right corner.
  const measured = Math.ceil(popover?.getBoundingClientRect?.().width || 0);
  const width = Math.min(maxInline, measured || rootCssLengthPx('--pane-tab-popover-inline-size') || maxInline);
  const height = Math.ceil(popover?.getBoundingClientRect?.().height || 0);
  const position = clampToViewport(
    Math.floor(rect.left),
    Math.ceil(rect.bottom) + bridgeGap,
    width,
    height,
    {edgeGap, minTop: topbarBottom + edgeGap},
  );
  document.documentElement.style.setProperty('--pane-tab-popover-top', `${Math.round(position.top)}px`);
  document.documentElement.style.setProperty('--pane-tab-popover-left', `${Math.round(position.left)}px`);
}

function paneInfoTabHtml(item = infoItemId, options = {}) {
  // DOIT.6: use .session-button-dir (like the Finder/Prefs tabs) so the label gets the themed
  // active/inactive colors; the old .pane-tab-info-label set no color and went white-on-white in light.
  return `<span class="pane-tab-core">${tabTypeIconHtml(item, options)}<span class="session-button-dir pane-tab-info-label">${esc(itemLabel(item))}</span></span>`;
}

function fileExplorerPaneTabHtml(item = fileExplorerItemId, options = {}) {
  return `<span class="pane-tab-core">${tabTypeIconHtml(item, options)}<span class="session-button-dir">${esc(fileExplorerLabel())}</span></span>`;
}

function preferencesPaneTabHtml(item = prefsItemId, options = {}) {
  return `<span class="pane-tab-core">${tabTypeIconHtml(item, options)}<span class="session-button-dir">${esc(t('tab.preferences'))}</span></span>`;
}

function changesPaneTabHtml(item = changesItemId, options = {}) {
  const count = sessionFilesPayload.files?.length || 0;
  const badge = count ? `<span class="session-state-badge changes-count-badge">${count}</span>` : '';
  return `<span class="pane-tab-core">${tabTypeIconHtml(item, options)}<span class="session-button-dir">${esc(t('tab.changes'))}</span>${badge}</span>`;
}

function fileEditorPaneTabHtml(item, options = {}) {
  const path = fileItemPath(item);
  const state = openFiles.get(path) || {};
  const owners = openFileOwnerSessionsForPath(path);
  const ownerTitle = owners.length > 1 ? t('filetab.ownersMulti', {sessions: owners.join(', ')}) : owners[0] ? t('filetab.owner', {session: owners[0]}) : '';
  const ownerText = owners.length > 1 ? t('filetab.multi') : owners[0] || '';
  const owner = ownerText ? `<span class="file-tab-owner" title="${esc(ownerTitle)}">${esc(ownerText)}</span>` : '';
  const dirty = state.dirty ? `<span class="file-tab-dirty" title="${esc(t('filetab.modified'))}" aria-label="${esc(t('filetab.modified'))}"></span>` : '';
  const missing = openFileIsMissing(path) ? `<span class="file-tab-missing-badge" title="${esc(t('filetab.missingTitle'))}" aria-label="${esc(t('filetab.missingTitle'))}">${esc(t('filetab.missing'))}</span>` : '';
  const kind = isFilePreviewItem(item) ? `<span class="file-tab-kind" title="${esc(t('tab.previewOnly'))}">${esc(t('tab.preview'))}</span>` : '';
  return `<span class="pane-tab-core">${tabTypeIconHtml(item, options)}<span class="session-button-text">${owner}${dirty}${missing}${kind}<span class="session-button-dir">${esc(basenameOf(path))}</span></span></span>`;
}

function tmuxPaneTabHtml(session, info, state, auto) {
  const pr = displayPullRequest(info);
  const desc = sessionTabDescription(session, info);
  const detailHtml = desc ? `<span class="session-button-dir tab-inline-detail">${esc(desc)}</span>` : '';
  return `<span class="pane-tab-core">${yoloMarkerHtml(session, auto, {enabledOnly: false, toggle: true, yoloWorking: sessionYoloIsWorking(session)})}<span class="session-button-prefix">${sessionNumberNameHtml(session)}</span>
    <span class="session-button-text">${state ? sessionStateHtml(state) : ''}${defaultBranchBadgeHtml(session, info)}${pullRequestCompactBadgesHtml(session, pr)}${detailHtml}</span></span>`;
}

function bindPaneTabStrip(strip, side) {
  strip.ondragover = event => {
    const filePayload = fileDragPayload(event);
    if (filePayload?.path) {
      event.preventDefault();
      event.stopImmediatePropagation();
      if (slotIsFileExplorerPane(side) || slotIsChangesPane(side)) {
        event.dataTransfer.dropEffect = 'none';
        clearPaneTabDropPreview(strip);
        return;
      }
      event.dataTransfer.dropEffect = 'copy';
      clearDropPreview();
      showPaneTabDropPreview(strip, event, '');
      return;
    }
    const payload = dragPayload(event);
    if (!payload?.session) return;
    event.preventDefault();
    event.stopImmediatePropagation();
    if (slotIsFileExplorerPane(side) || slotIsChangesPane(side)) {
      event.dataTransfer.dropEffect = 'none';
      clearPaneTabDropPreview(strip);
      return;
    }
    event.dataTransfer.dropEffect = 'move';
    clearDropPreview();
    showPaneTabDropPreview(strip, event, payload.session);
  };
  strip.ondragleave = event => {
    event.stopImmediatePropagation();
    if (!strip.contains(event.relatedTarget)) clearPaneTabDropPreview(strip);
  };
  strip.ondrop = event => {
    const filePayload = fileDragPayload(event);
    if (filePayload?.path) {
      clearPaneTabDropPreview(strip);
      event.preventDefault();
      event.stopImmediatePropagation();
      if (slotIsFileExplorerPane(side) || slotIsChangesPane(side)) return;
      openDraggedFilesInEditor(filePayload, {targetSlot: side, targetIndex: paneTabDropIndex(strip, event, '')});
      return;
    }
    const payload = dragPayload(event);
    clearPaneTabDropPreview(strip);
    if (!payload?.session) return;
    event.preventDefault();
    event.stopImmediatePropagation();
    if (slotIsFileExplorerPane(side) || slotIsChangesPane(side)) return;
    moveSessionToSlot(payload.session, side, payload.sourceSlot || slotForSession(payload.session), paneTabDropIndex(strip, event, payload.session));
  };
}

function showPaneTabDropPreview(strip, event, movingSession) {
  const placement = paneTabDropPlacement(strip, event, movingSession);
  strip.style.setProperty('--tab-drop-x', `${Math.round(placement.x)}px`);
  strip.style.setProperty('--tab-drop-y', `${Math.round(placement.y)}px`);
  strip.style.setProperty('--tab-drop-height', `${Math.round(placement.height)}px`);
  strip.classList.add('drag-over', 'tab-drop-preview');
}

function clearPaneTabDropPreview(strip) {
  strip.classList.remove('drag-over', 'tab-drop-preview');
  strip.style.removeProperty('--tab-drop-x');
  strip.style.removeProperty('--tab-drop-y');
  strip.style.removeProperty('--tab-drop-height');
}

// #47: reset the per-drag tab-rect cache (called at drag start/end). See dragMeasureStrip.
function resetDragTabRectCache() {
  dragTabRectCache = null;
}

// During a live drag the tabs do not move (renders are deferred, #30), so measure each strip's rect +
// its tab rects ONCE and reuse them for every dragover instead of forcing sync layout on every move.
// Outside a drag (e.g. unit tests calling paneTabDropPlacement directly), measure fresh each time.
function dragMeasureStrip(strip) {
  if (dragSession != null) {
    if (!dragTabRectCache || dragTabRectCache.strip !== strip) {
      dragTabRectCache = {strip, stripRect: strip.getBoundingClientRect(), rects: new Map()};
    }
    return dragTabRectCache;
  }
  return {strip, stripRect: strip.getBoundingClientRect(), rects: new Map()};
}

function dragMeasureTab(cache, tab) {
  let rect = cache.rects.get(tab);
  if (!rect) {
    rect = tab.getBoundingClientRect();
    cache.rects.set(tab, rect);
  }
  return rect;
}

function paneTabDropPlacement(strip, event, movingSession) {
  const allTabs = Array.from(strip.querySelectorAll('.pane-tab'));
  // The source's position in the FULL strip (before filtering) drives a directional insert threshold
  // for same-strip reorder; -1 means a cross-pane move (keep the centered threshold).
  const sourceVisualIndex = movingSession ? allTabs.findIndex(tab => tab.dataset.paneTab === movingSession) : -1;
  const tabs = allTabs.filter(tab => tab.dataset.paneTab !== movingSession);
  const measure = dragMeasureStrip(strip);
  const stripRect = measure.stripRect;
  const clampX = value => Math.max(2, Math.min(stripRect.width - 2, value));
  const clampY = (value, height) => Math.max(0, Math.min(Math.max(0, stripRect.height - height), value));
  const defaultHeight = Math.min(32, Math.max(24, stripRect.height || 27));
  if (!tabs.length) {
    return {
      index: 0,
      x: clampX(event.clientX - stripRect.left),
      y: clampY(event.clientY - stripRect.top - defaultHeight / 2, defaultHeight),
      height: defaultHeight,
    };
  }
  const rows = paneTabRows(tabs, tab => dragMeasureTab(measure, tab));
  const row = rows.reduce((best, item) => {
    const distance = Math.abs(event.clientY - item.centerY);
    return !best || distance < best.distance ? {row: item, distance} : best;
  }, null)?.row || rows[0];
  const rowTabs = row.items.slice().sort((left, right) => left.rect.left - right.rect.left);
  const sameStrip = sourceVisualIndex >= 0;
  for (const item of rowTabs) {
    const rect = item.rect;
    // Cross-pane drops insert at the tab center. Same-strip reorder uses the FAR edge relative to the
    // source (item.index >= sourceVisualIndex means the source sits to its LEFT) so dropping the source
    // anywhere on a neighbor moves it PAST that neighbor — fixes left->right needing a center overshoot.
    let threshold = rect.left + rect.width / 2;
    if (sameStrip) threshold = item.index >= sourceVisualIndex ? rect.left : rect.right;
    if (event.clientX < threshold) {
      return {
        index: item.index,
        x: clampX(rect.left - stripRect.left),
        y: clampY(row.top - stripRect.top, row.height),
        height: row.height,
      };
    }
  }
  const last = rowTabs[rowTabs.length - 1];
  return {
    index: last.index + 1,
    x: clampX(last.rect.right - stripRect.left),
    y: clampY(row.top - stripRect.top, row.height),
    height: row.height,
  };
}

function paneTabRows(tabs, rectFor = tab => tab.getBoundingClientRect()) {
  const rows = [];
  tabs.forEach((tab, index) => {
    const rect = rectFor(tab);
    const centerY = rect.top + rect.height / 2;
    const row = rows.find(item => Math.abs(centerY - item.centerY) <= Math.max(4, item.height / 2));
    const target = row || {items: [], top: rect.top, bottom: rect.bottom, centerY, height: rect.height};
    target.items.push({index, rect});
    target.top = Math.min(target.top, rect.top);
    target.bottom = Math.max(target.bottom, rect.bottom);
    target.height = Math.max(1, target.bottom - target.top);
    target.centerY = target.top + target.height / 2;
    if (!row) rows.push(target);
  });
  return rows.sort((left, right) => left.top - right.top);
}

function paneTabDropIndex(strip, event, movingSession) {
  return paneTabDropPlacement(strip, event, movingSession).index;
}

function getOrCreatePanel(session) {
  let panel = panelNodes.get(session);
  if (panel) return panel;
  const type = tabTypeForItem(session);
  if (type?.createPanel) panel = type.createPanel(session);
  else panel = createPanel(session);
  panelNodes.set(session, panel);
  panelPool.appendChild(panel);
  return panel;
}

function bindPanelShell(panel, session) {
  // Inactive-pane dimming is pure CSS now (`.panel:not(.focused-pane) .panel-overlay-root::after`,
  // keyed off the uniformly-toggled .focused-pane class) — no per-pane overlay <div> to install.
  bindPanelPopover(panel);
  bindPaneFrameControls(panel, session);
  panel.addEventListener('pointerenter', () => selectPanelOnHover(session));
  panel.addEventListener('pointerdown', event => {
    if (!isTmuxSession(session)) {
      setFocusedPanelItem(session, {
        focusPreferencesSearch: !preferenceFocusTargetIsInteractive(event.target),
      });
    }
  }, {capture: true});
  panel.addEventListener('focusin', event => {
    if (!isTmuxSession(session)) {
      setFocusedPanelItem(session, {
        focusPreferencesSearch: !preferenceFocusTargetIsInteractive(event.target),
      });
    }
  });
  const head = panel.querySelector('.panel-head');
  if (head) {
    head.draggable = true;
    head.dataset.dragSession = session;
    head.addEventListener('dragstart', event => startSessionDrag(event, session, head.dataset.dragSlot || null));
    head.addEventListener('dragend', endSessionDrag);
    head.addEventListener('dragover', event => {
      const filePayload = fileDragPayload(event);
      if (filePayload?.path) {
        event.preventDefault();
        event.stopPropagation();
        clearDropPreview();
        const targetSlot = head.dataset.dragSlot || slotForSession(session);
        if (slotIsFileExplorerPane(targetSlot) || slotIsChangesPane(targetSlot)) {
          event.dataTransfer.dropEffect = 'none';
          return;
        }
        event.dataTransfer.dropEffect = 'copy';
        head.classList.add('tab-drag-over');
        return;
      }
      const payload = dragPayload(event);
      if (!payload?.session) return;
      event.preventDefault();
      event.stopPropagation();
      clearDropPreview();
      if (event.target.closest('.pane-tabs')) return;
      const targetSlot = head.dataset.dragSlot || slotForSession(session);
      if (slotIsFileExplorerPane(targetSlot) || slotIsChangesPane(targetSlot)) {
        event.dataTransfer.dropEffect = 'none';
        return;
      }
      event.dataTransfer.dropEffect = 'move';
      head.classList.add('tab-drag-over');
    });
    head.addEventListener('dragleave', event => {
      if (!head.contains(event.relatedTarget)) head.classList.remove('tab-drag-over');
    });
    head.addEventListener('drop', event => {
      const filePayload = fileDragPayload(event);
      if (filePayload?.path && !event.target.closest('.pane-tabs')) {
        head.classList.remove('tab-drag-over');
        event.preventDefault();
        event.stopPropagation();
        const targetSlot = head.dataset.dragSlot || slotForSession(session);
        if (slotIsFileExplorerPane(targetSlot) || slotIsChangesPane(targetSlot)) return;
        if (targetSlot) openDraggedFilesInEditor(filePayload, {targetSlot});
        return;
      }
      const payload = dragPayload(event);
      head.classList.remove('tab-drag-over');
      if (!payload?.session || event.target.closest('.pane-tabs')) return;
      event.preventDefault();
      event.stopPropagation();
      const targetSlot = head.dataset.dragSlot || slotForSession(session);
      if (!targetSlot) return;
      if (slotIsFileExplorerPane(targetSlot) || slotIsChangesPane(targetSlot)) return;
      if (isFileExplorerItem(payload.session)) {
        dockFileExplorerPane();
        return;
      }
      moveSessionToSlot(payload.session, targetSlot, payload.sourceSlot || slotForSession(payload.session), paneTabs(targetSlot).length);
    });
  }
  panel.querySelector('[data-detail-toggle]')?.addEventListener('click', event => {
    event.preventDefault();
    event.stopPropagation();
    setPanelDetailsCollapsed(panel, !panel.classList.contains('details-collapsed'));
  });
}

function bindPaneFrameControls(panel, session) {
  if (!panel || panel.dataset.frameControlsBound === 'true') return;
  panel.dataset.frameControlsBound = 'true';
  panel.addEventListener('click', async event => {
    const button = event.target.closest('[data-pane-actions], [data-pane-minimize], [data-pane-expand], [data-pane-close]');
    if (!button || !panel.contains(button)) return;
    event.preventDefault();
    event.stopPropagation();
    event.stopImmediatePropagation?.();
    if (button.dataset.paneActions !== undefined) {
      const rect = button.getBoundingClientRect();
      showSessionContextMenu(button.dataset.paneActions || session, rect.left, rect.bottom + 4);
      return;
    }
    if (button.dataset.paneMinimize !== undefined) {
      minimizePaneFromLayout(button.dataset.paneMinimize || session);
      return;
    }
    if (button.dataset.paneExpand !== undefined) {
      expandPaneFromLayout(button.dataset.paneExpand || session);
      return;
    }
    if (button.dataset.paneClose !== undefined) {
      removePaneFromLayout(button.dataset.paneClose || session);
    }
  }, true);
}

function bindPanelPopover(panel) {
  const zone = panel.querySelector('.panel-popover-zone');
  if (!zone || zone.dataset.popoverBound === 'true') return;
  zone.dataset.popoverBound = 'true';
  createHoverPopover({
    anchor: zone,
    popover: () => zone.querySelector(':scope > .session-popover'),
    showDelay: 0,
    hideDelay: () => popoverHideDelayMs,
  });
}

function setPanelDetailsCollapsed(panel, collapsed) {
  panel.classList.toggle('details-collapsed', collapsed);
  const button = panel.querySelector('[data-detail-toggle]');
  if (button) {
    button.classList.toggle('active', !collapsed);
    const detailsLabel = collapsed ? t('pane.details.show') : t('pane.details.hide');
    button.title = detailsLabel;
    button.setAttribute('aria-label', detailsLabel);
    button.setAttribute('aria-pressed', collapsed ? 'false' : 'true');
  }
}

function terminalTabLabel(session, info) {
  const type = tabTypeForItem(session);
  if (type?.shortLabel) return type.shortLabel(session);
  const label = terminalProcessLabel(info);
  return shortText(label || 'Term', 16);
}

function terminalTabTitle(session, info) {
  const type = tabTypeForItem(session);
  if (type?.terminalTitle) return type.terminalTitle(session);
  return `terminal: ${terminalProcessLabel(info) || 'Term'}`;
}

function terminalProcessLabel(info) {
  const pane = terminalDisplayPane(info);
  if (pane?.process_label) return pane.process_label;
  const agent = agentForPane(info, pane) || info?.agents?.[0];
  if (agent?.command) return processLabelFromCommand(agent.command);
  if (agent?.kind) return agent.kind;
  if (pane?.command) return pane.command;
  return 'Term';
}

function terminalDisplayPane(info) {
  const panes = Array.isArray(info?.panes) ? info.panes : [];
  return panes.find(pane => pane.window_active && pane.active)
    || panes.find(pane => pane.window_active)
    || info?.selected_pane
    || panes[0]
    || null;
}

function tmuxWindowNumber(value) {
  const number = Number(value);
  return Number.isFinite(number) ? number : null;
}

function tmuxWindowIndices(panes) {
  const windows = [];
  const seen = new Set();
  for (const pane of Array.isArray(panes) ? panes : []) {
    const index = tmuxWindowNumber(pane.window);
    if (index === null || seen.has(index)) continue;
    seen.add(index);
    windows.push(index);
  }
  return windows.sort((left, right) => left - right);
}

function windowStepVisibility(panes) {
  const windows = tmuxWindowIndices(panes);
  if (windows.length <= 1) return {prev: false, next: false};
  const activeIndex = tmuxWindowNumber((Array.isArray(panes) ? panes : []).find(pane => pane.window_active)?.window) ?? windows[0];
  return {
    prev: windows.some(index => index < activeIndex),
    next: windows.some(index => index > activeIndex),
  };
}

function previewTmuxWindowInfo(info, key) {
  const panes = Array.isArray(info?.panes) ? info.panes : [];
  const windows = tmuxWindowIndices(panes);
  if (windows.length < 2) return null;
  const activePane = terminalDisplayPane(info);
  const activeIndex = tmuxWindowNumber(activePane?.window);
  const current = Math.max(0, windows.findIndex(index => index === activeIndex));
  const delta = key === 'p' ? -1 : 1;
  const target = windows[(current + delta + windows.length) % windows.length];
  const nextPanes = panes.map(pane => ({...pane, window_active: tmuxWindowNumber(pane.window) === target}));
  return {
    ...info,
    panes: nextPanes,
    selected_pane: nextPanes.find(pane => pane.window_active && pane.active)
      || nextPanes.find(pane => pane.window_active)
      || info?.selected_pane
      || null,
  };
}

function previewTmuxWindowLabel(session, key) {
  const info = transcriptMeta.sessions?.[session];
  const nextInfo = previewTmuxWindowInfo(info, key);
  if (!nextInfo) return;
  transcriptMeta = {
    ...transcriptMeta,
    sessions: {
      ...(transcriptMeta.sessions || {}),
      [session]: nextInfo,
    },
  };
  updatePanelControlLabels(session, nextInfo);
}

function handleWindowStepButtonClick(event) {
  const button = event.currentTarget;
  const key = button.dataset.windowDir === 'prev' ? 'p' : 'n';
  const label = button.dataset.windowDir === 'prev' ? 'previous tmux window' : 'next tmux window';
  tmuxWindow(button.dataset.windowSession, key, label);
}

function createWindowStepButton(session, dir) {
  const label = windowStepButtonLabel(dir);
  const button = document.createElement('button');
  button.className = 'tab tmux-window-step';
  button.dataset.windowStepButton = dir;
  button.textContent = dir === 'prev' ? '<' : '>';
  if (readOnlyMode) {
    button.type = 'button';
    button.disabled = true;
    button.title = `${label} tmux window requires admin access`;
    return button;
  }
  button.dataset.windowDir = dir;
  button.dataset.windowSession = session;
  button.title = `${label} tmux window`;
  button.addEventListener('click', handleWindowStepButtonClick);
  return button;
}

function syncWindowStepButton(controls, terminalButton, session, dir, visible) {
  const selector = `[data-window-step-button="${dir}"]`;
  const existing = controls.querySelector(selector);
  if (!visible) {
    existing?.remove();
    return;
  }
  if (existing) return;
  const button = createWindowStepButton(session, dir);
  if (dir === 'prev') controls.insertBefore(button, terminalButton);
  else controls.insertBefore(button, terminalButton.nextSibling || null);
}

function updatePanelWindowStepButtons(session, info) {
  const controls = document.getElementById(`panel-${session}`)?.querySelector('.tabs');
  const terminalButton = controls?.querySelector('.terminal-tab');
  if (!controls || !terminalButton) return;
  const steps = windowStepVisibility(info?.panes);
  syncWindowStepButton(controls, terminalButton, session, 'prev', steps.prev);
  syncWindowStepButton(controls, terminalButton, session, 'next', steps.next);
}

function agentForPane(info, pane) {
  if (!pane || !Array.isArray(info?.agents)) return null;
  return info.agents.find(agent => agent.pane_target === pane.target) || null;
}

function processLabelFromCommand(command) {
  const tokens = String(command || '').trim().split(/\s+/).filter(Boolean);
  if (!tokens.length) return '';
  const base = pathBasename(tokens[0]) || tokens[0];
  const lower = base.toLowerCase();
  if (lower.startsWith('python') && tokens[1] && !tokens[1].startsWith('-')) return pathBasename(tokens[1]) || tokens[1];
  if (lower === 'node' && tokens[1] && !tokens[1].startsWith('-')) return pathBasename(tokens[1]) || tokens[1];
  return base;
}

function updatePanelControlLabels(session, info) {
  const button = document.querySelector(`[data-tab="${cssEscape(session)}"][data-tab-name="terminal"]`);
  updatePanelWindowStepButtons(session, info);
  if (button) {
    button.textContent = terminalTabLabel(session, info);
    button.title = terminalTabTitle(session, info);
  }
}

// DOIT.6 #40: ONE merged panel hosting both YO!info (repo metadata) and YO!agent (chat + activity
// summary), switched by a segmented sub-tab row under the pane tabs. Both sub-views render into their
// own containers (#info-content / #yoagent-content) and the active one is shown via CSS; the chosen
// sub-tab is remembered across reloads (infoPanelSubTab).
function createInfoPanel() {
  const panel = document.createElement('article');
  panel.className = 'panel info-panel';
  panel.id = `panel-${infoItemId}`;
  panel.dataset.infoSubtab = infoPanelSubTab;
  panel.innerHTML = `
      <div class="panel-head">
        ${virtualPanelControlsHtml(infoItemId, infoTabLabel())}
        <div class="pane-tabs" role="tablist" aria-label="${esc(t('pane.tabs.aria'))}"></div>
      </div>
      <div class="panel-detail-row">
        <div class="panel-copy">
          <div id="panel-tab-${infoItemId}" class="panel-session-label"><span class="session-button-dir">${esc(infoTabLabel())}</span></div>
          <div id="meta-${infoItemId}" class="meta">${esc(t('info.subtitle'))}</div>
        </div>
        <button type="button" class="panel-detail-close" data-detail-toggle="${esc(infoItemId)}" title="${esc(t('pane.details.hide'))}" aria-label="${esc(t('pane.details.hide'))}"></button>
      </div>
      <div class="info-subtabs" role="tablist" aria-label="${esc(infoTabLabel())} / ${esc(yoagentTabLabel())}">
        <button type="button" class="info-subtab" role="tab" data-info-subtab="info"><span class="session-button-dir">${esc(infoTabLabel())}</span></button>
        <button type="button" class="info-subtab" role="tab" data-info-subtab="yoagent"><span class="session-button-dir">${esc(yoagentTabLabel())}</span></button>
      </div>
      <div class="info-pane panel-overlay-root">
        <div id="panel-toasts-${infoItemId}" class="panel-toast-stack"></div>
        <div class="info-subview" data-info-subview="info">
          <div class="transcript-head info-head">
            <span>${esc(infoTabLabel())}</span>
            <button type="button" class="info-refresh" data-info-refresh title="${esc(t('info.refreshRepo'))}">${esc(t('info.refreshRepo'))}</button>
          </div>
          <div id="info-content" class="info-list"></div>
          <div id="info-watched" class="info-watched"></div>
        </div>
        <div class="info-subview yoagent-subview" data-info-subview="yoagent">
          <div class="transcript-head info-head">
            <span>${esc(yoagentTabLabel())}</span>
            <button type="button" class="info-refresh" data-yoagent-refresh title="${esc(t('yoagent.refreshTitle'))}">${esc(t('yoagent.refresh'))}</button>
          </div>
          <div id="yoagent-content" class="info-list yoagent-list"></div>
        </div>
      </div>`;
  bindPanelShell(panel, infoItemId);
  panel.querySelector('[data-info-refresh]')?.addEventListener('click', event => {
    event.preventDefault();
    refreshTranscripts();
  });
  panel.querySelector('[data-yoagent-refresh]')?.addEventListener('click', event => {
    event.preventDefault();
    refreshActivitySummary({force: true});
  });
  panel.querySelectorAll('[data-info-subtab]').forEach(button => {
    button.addEventListener('click', event => {
      event.preventDefault();
      setInfoSubTab(button.dataset.infoSubtab, {focusChat: button.dataset.infoSubtab === 'yoagent'});
    });
  });
  // YO!agent chat interactions (submit / clear / retry / draft) — preserved from the old yoagent panel.
  panel.addEventListener('submit', event => {
    const form = event.target.closest('[data-yoagent-chat-form]');
    if (!form || !panel.contains(form)) return;
    event.preventDefault();
    const input = form.querySelector('[data-yoagent-chat-input]');
    const value = input?.value || '';
    if (input) input.value = '';
    yoagentDraft = '';
    sendYoagentChatMessage(value);
  });
  panel.addEventListener('click', event => {
    const clear = event.target.closest('[data-yoagent-clear]');
    if (clear && panel.contains(clear)) {
      event.preventDefault();
      clearYoagentConversation();
      return;
    }
    const retry = event.target.closest('[data-yoagent-retry]');
    if (retry && panel.contains(retry)) {
      event.preventDefault();
      const input = panel.querySelector('[data-yoagent-chat-input]');
      sendYoagentChatMessage(input?.value || yoagentDraft);
    }
  });
  panel.addEventListener('input', event => {
    const input = event.target.closest('[data-yoagent-chat-input]');
    if (input && panel.contains(input)) yoagentDraft = input.value || '';
  });
  panel.addEventListener('change', event => {
    // The composer's backend pill writes the real yoagent.backend setting and re-renders (which also
    // flips chat enablement when switching to/from No agent).
    const backend = event.target.closest('[data-yoagent-backend]');
    if (!backend || !panel.contains(backend) || readOnlyMode) return;
    saveSettingsPatch(settingPatch('yoagent.backend', backend.value))
      .then(() => { statusEl.textContent = `YO!agent backend: ${yoagentBackendLabel(backend.value)}`; renderYoagentPanel(); })
      .catch(error => { statusErr(`settings save failed: ${esc(error)}`); refreshSettings({force: true}); });
  });
  applyInfoSubTab(panel);
  renderInfoPanel();
  renderYoagentPanel();
  return panel;
}

// Reflect the active sub-tab onto the merged panel (button highlight + which sub-view is visible).
function applyInfoSubTab(panel = document.getElementById(`panel-${infoItemId}`)) {
  if (!panel) return;
  panel.dataset.infoSubtab = infoPanelSubTab;
  panel.querySelectorAll('[data-info-subtab]').forEach(button => {
    const active = button.dataset.infoSubtab === infoPanelSubTab;
    button.classList.toggle('active', active);
    button.setAttribute('aria-selected', active ? 'true' : 'false');
  });
  panel.querySelectorAll('[data-info-subview]').forEach(view => {
    view.classList.toggle('active', view.dataset.infoSubview === infoPanelSubTab);
  });
}

function setInfoSubTab(tab, options = {}) {
  const next = normalizedInfoSubTab(tab);
  if (next !== infoPanelSubTab) {
    infoPanelSubTab = next;
    writeStoredInfoSubTab(next);
  }
  applyInfoSubTab();
  if (next === 'yoagent') renderYoagentPanel({preserveDraft: true, focusInput: options.focusChat === true});
}

// Open the merged YO!info pane on a given sub-tab — used by the File menu, command palette, the topbar
// activity button, and the boot deep-link for legacy ?…=yoagent / __yoagent__ references.
async function openInfoSubTab(tab) {
  infoPanelSubTab = normalizedInfoSubTab(tab);
  writeStoredInfoSubTab(infoPanelSubTab);
  await selectSession(infoItemId);
  applyInfoSubTab();
  if (infoPanelSubTab === 'yoagent') renderYoagentPanel({preserveDraft: true, focusInput: true});
}

function sessionActivitySummary(session) {
  return activitySummaryPayload?.sessions?.[session] || null;
}

function activitySummaryLinesHtml(lines, options = {}) {
  const items = Array.isArray(lines) ? lines.filter(Boolean) : [];
  if (!items.length) return options.empty ? `<div class="yoagent-empty">${esc(options.empty)}</div>` : '';
  return items.map(line => `<div class="yoagent-line">${esc(line)}</div>`).join('');
}

function relativeActivityGeneratedText(payload = activitySummaryPayload) {
  const ts = Number(payload?.generated_ts || 0) || Date.parse(payload?.generated_at || '') / 1000;
  if (!Number.isFinite(ts) || ts <= 0) return {text: t('yoagent.notLoaded'), title: ''};
  const seconds = Math.max(0, Math.round(Date.now() / 1000 - ts));
  // DOIT.8 Phase 3: render the relative time with Intl.RelativeTimeFormat(activeLocale) for native
  // locale phrasing, wrapped by the localized "last updated {rel}" string.
  const text = seconds < 60
    ? t('yoagent.updated.justNow')
    : t('yoagent.updated.wrap', {rel: relativeTimeFormat(seconds)});
  let title = payload?.generated_at || '';
  try {
    title = new Intl.DateTimeFormat(undefined, {
      timeZone: 'America/Los_Angeles',
      dateStyle: 'medium',
      timeStyle: 'medium',
      timeZoneName: 'short',
    }).format(new Date(ts * 1000));
  } catch (_) {}
  return {text, title};
}

function globalActivitySummaryHtml() {
  const summary = activitySummaryPayload?.global || {};
  const lines = Array.isArray(summary.lines) ? summary.lines : [];
  const headline = summary.headline || lines[0] || '';
  const detailLines = lines.filter(line => line && line !== headline && !/^Session\s+\S+:/i.test(String(line)));
  const generated = relativeActivityGeneratedText();
  const refreshBar = activitySummaryRefreshing ? `<div class="yoagent-refresh-progress" aria-label="${esc(t('yoagent.refreshing'))}"></div>` : '';
  return `<section class="yoagent-global" aria-label="${esc(t('yoagent.globalAria', {name: yoagentTabLabel()}))}">
    <div class="yoagent-global-head">
      <span>${esc(yoagentTabLabel())}</span>
      <span class="yoagent-generated" title="${esc(generated.title)}">(${esc(generated.text)})</span>
    </div>
    ${refreshBar}
    ${headline ? `<div class="yoagent-headline">${esc(headline)}</div>` : activitySummaryLinesHtml([], {empty: t('yoagent.emptyGlobal')})}
    ${activitySummaryLinesHtml(detailLines)}
  </section>`;
}

function yoagentSessionSummariesHtml() {
  const sessions = activitySummaryPayload?.sessions || {};
  const order = Array.isArray(activitySummaryPayload?.session_order) ? activitySummaryPayload.session_order : Object.keys(sessions);
  const rows = order
    .map(session => {
      const summary = sessions?.[session];
      if (!summary?.local) return '';
      const status = summary.active ? 'active' : 'idle';
      const files = summary.files?.count ? t('yoagent.files', {count: summary.files.count, added: summary.files.added || 0, removed: summary.files.removed || 0}) : t('yoagent.noFiles');
      return `<article class="yoagent-session-summary ${esc(status)}">
        <div class="yoagent-session-summary-head">
          <span>${esc(t('yoagent.sessionLabel', {session}))}</span>
          <span>${esc(summary.agent_label || summary.agent || t('yoagent.agentFallback'))}</span>
          <span>${esc(files)}</span>
        </div>
        <div class="yoagent-session-summary-body markdown-body" data-yoagent-summary-markdown>${esc(summary.local)}</div>
      </article>`;
    })
    .filter(Boolean)
    .join('');
  return `<section class="yoagent-session-summaries" aria-label="${esc(t('yoagent.perSessionAria'))}">
    ${rows || `<div class="yoagent-empty">${esc(t('yoagent.emptyPerSession'))}</div>`}
  </section>`;
}

function yoagentChatMessagesHtml() {
  const messages = Array.isArray(yoagentMessages) ? yoagentMessages : [];
  if (!messages.length) {
    if (!yoagentChatEnabled()) {
      return `<div class="yoagent-chat-empty">${esc(t('yoagent.chatDisabled'))}</div>`;
    }
    return `<div class="yoagent-chat-empty">${esc(t('yoagent.chatEmpty', {name: yoagentTabLabel()}))}</div>`;
  }
  return messages.map(message => {
    const role = message.role === 'user' ? t('yoagent.you') : yoagentTabLabel();
    const roleClass = message.role === 'user' ? 'user' : 'assistant';
    // Assistant replies are Markdown (numbered sections, bold titles, sub-bullets); flag the body so
    // renderYoagentMessageMarkdown() can render it. The escaped text stays as the no-marked fallback.
    const bodyClass = roleClass === 'assistant' ? 'yoagent-message-body markdown-body' : 'yoagent-message-body';
    const markdownAttr = roleClass === 'assistant' ? ' data-yoagent-markdown' : '';
    return `<div class="yoagent-message ${roleClass}">
      <div class="yoagent-message-role">${esc(role)}</div>
      <div class="${bodyClass}"${markdownAttr}>${esc(message.content || '')}</div>
    </div>`;
  }).join('');
}

function yoagentNoticeHtml() {
  if (!yoagentNotice?.reason) return '';
  const backend = yoagentNotice.backend ? `<span class="yoagent-chat-notice-backend">${esc(yoagentNotice.backend)}</span> ` : '';
  return `<div class="yoagent-chat-notice">${backend}${esc(yoagentNotice.reason)}</div>`;
}

function yoagentBackendLabel(value) {
  const key = String(value || '').toLowerCase();
  if (key === 'auto') return t('yoagent.backend.auto');
  if (key === 'deterministic') return t('yoagent.backend.none');
  if (key === 'codex') return 'Codex';
  if (key === 'claude') return 'Claude';
  return value || t('yoagent.backend.none');
}

function yoagentBackendKey() {
  return String(initialSetting('yoagent.backend', 'auto') || 'auto').trim().toLowerCase();
}

// #41: mirror the server's auto-resolution (codex -> claude -> deterministic) using the cached agent
// login status, so the chat input enables/disables to match what the backend will actually run.
function yoagentResolvedBackend() {
  const key = yoagentBackendKey();
  if (key !== 'auto') return key;
  for (const agent of ['codex', 'claude']) {
    if (availableAgents.has(agent) && agentLoggedIn(agent)) return agent;
  }
  return 'deterministic';
}

function yoagentChatEnabled() {
  return ['claude', 'codex'].includes(yoagentResolvedBackend());
}

// The composer's "Auto" pill = the real yoagent.backend setting (Auto / Claude / Codex / No agent),
// rendered as a styled select so it can be changed inline (the mockup's mode pill). No other mockup
// pills are rendered — they have no YO!agent mapping.
function yoagentBackendPillHtml(disabled) {
  const current = yoagentBackendKey();
  // Only Auto / Claude / Codex are selectable. "No agent" (deterministic) stays as an internal
  // auto-fallback when no agent is logged in, but is never offered as a pick.
  const options = ['auto', 'claude', 'codex']
    .map(value => `<option value="${esc(value)}"${value === current ? ' selected' : ''}>${esc(yoagentBackendLabel(value))}</option>`)
    .join('');
  return `<label class="yoagent-backend-pill" title="${esc(t('pref.yoagent.backend.label'))}">
    <span class="yoagent-backend-pill-dot" aria-hidden="true"></span>
    <select data-yoagent-backend aria-label="${esc(t('pref.yoagent.backend.label'))}"${disabled}>${options}</select>
  </label>`;
}

function yoagentChatHtml() {
  const disabled = yoagentBusy || readOnlyMode ? ' disabled' : '';
  const placeholder = readOnlyMode ? t('yoagent.chatAdminPlaceholder', {name: yoagentTabLabel()}) : t('yoagent.chatPlaceholder');
  const hasConversation = Boolean(yoagentMessages.length || yoagentNotice || yoagentBusy || yoagentError);
  // Strip any trailing dots/ellipsis from the localized label so the three animated dots carry the motion.
  const thinkingLabel = esc(t('yoagent.thinking').replace(/[.…\s]+$/, ''));
  const busy = yoagentBusy
    ? `<div class="yoagent-chat-status"><span class="session-yolo-marker active working yoagent-chat-spinner" style="--yolo-rotate-delay: ${esc(yoloRotationDelay())}" aria-hidden="true">${esc(t('brand.marker'))}</span><span class="yoagent-thinking">${thinkingLabel}<span class="yoagent-thinking-dots" aria-hidden="true"><i>.</i><i>.</i><i>.</i></span></span></div>`
    : '';
  const retry = yoagentError && yoagentDraft && yoagentChatEnabled() && !yoagentBusy && !readOnlyMode
    ? `<button type="button" class="yoagent-chat-retry" data-yoagent-retry>${esc(t('yoagent.retry'))}</button>`
    : '';
  const error = yoagentError ? `<div class="yoagent-chat-error"><span>${esc(yoagentError)}</span>${retry}</div>` : '';
  const clearDisabled = yoagentBusy || (!yoagentMessages.length && !yoagentNotice && !yoagentError) ? ' disabled' : '';
  const form = yoagentChatEnabled()
    ? `<form class="yoagent-chat-form" data-yoagent-chat-form>
      <input type="text" class="yoagent-chat-input" data-yoagent-chat-input value="${esc(yoagentDraft)}" placeholder="${esc(placeholder)}"${disabled}>
      <div class="yoagent-chat-controls">
        ${yoagentBackendPillHtml(disabled)}
        <span class="yoagent-chat-controls-spacer"></span>
        <button type="button" class="yoagent-chat-clear" data-yoagent-clear${clearDisabled}>${esc(t('yoagent.clear'))}</button>
        <button type="submit" class="yoagent-chat-send"${disabled} title="${esc(t('yoagent.ask'))}" aria-label="${esc(t('yoagent.ask'))}">
          <svg class="yoagent-chat-send-icon" viewBox="0 0 24 24" aria-hidden="true"><path d="M5 12h12M12 6l6 6-6 6" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"/></svg>
        </button>
      </div>
    </form>`
    : '';
  return `<section class="yoagent-chat ${hasConversation ? 'has-history' : 'empty'}" aria-label="${esc(t('yoagent.chatAria', {name: yoagentTabLabel()}))}">
    <div class="yoagent-chat-history">${yoagentNoticeHtml()}${yoagentChatMessagesHtml()}${busy}${error}</div>
    ${form}
  </section>`;
}

function yoagentChatNetworkError(error) {
  const text = String(error?.message || error || '');
  return error instanceof TypeError || /failed to fetch|networkerror|load failed|fetch failed/i.test(text);
}

function yoagentChatErrorMessage(error) {
  if (yoagentChatNetworkError(error)) {
    return t('yoagent.networkError');
  }
  return t('yoagent.chatFailed', {error: error?.message || error});
}

async function clearYoagentConversation() {
  yoagentMessages = [];
  yoagentBusy = false;
  yoagentError = '';
  yoagentDraft = '';
  yoagentNotice = null;
  renderYoagentPanel({preserveDraft: false, scrollBottom: true});
  try {
    await apiFetch('/api/yoagent/reset', {method: 'POST'});
    statusEl.textContent = t('yoagent.statusCleared');
  } catch (error) {
    statusErr(`${esc(t('yoagent.statusClearFailed', {error}))}`);
  }
}

async function sendYoagentChatMessage(rawText) {
  const text = String(rawText || '').trim();
  if (!text || yoagentBusy || readOnlyMode || !yoagentChatEnabled()) return;
  yoagentMessages.push({role: 'user', content: text});
  yoagentDraft = '';
  yoagentBusy = true;
  yoagentError = '';
  yoagentNotice = null;
  renderYoagentPanel({preserveDraft: false, scrollBottom: true});
  try {
    const response = await apiFetch('/api/yoagent/chat', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      // DOIT.8 Phase 1: pass the active UI locale so the LLM backend replies in that language.
      body: JSON.stringify({message: text, history: yoagentMessages.slice(-10), locale: i18nActiveLocaleId()}),
    });
    const payload = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(payload.error || `HTTP ${response.status}`);
    if (payload.fallback && payload.fallback_reason) {
      yoagentNotice = {backend: yoagentBackendLabel(payload.backend_used || payload.backend), reason: payload.fallback_reason};
    }
    yoagentMessages.push({role: 'assistant', content: payload.answer || t('yoagent.noAnswer')});
    statusEl.textContent = t('yoagent.statusAnswered', {backend: yoagentBackendLabel(payload.backend_used || payload.backend)});
  } catch (error) {
    if (yoagentChatNetworkError(error)) yoagentDraft = text;
    yoagentError = yoagentChatErrorMessage(error);
  } finally {
    yoagentBusy = false;
    renderYoagentPanel({preserveDraft: true, scrollBottom: true, focusInput: true});
  }
}

async function refreshActivitySummary(options = {}) {
  if (activitySummaryRefreshing && options.force !== true) return;
  const requestId = ++activitySummaryRequestId;
  const requestIsCurrent = () => requestId === activitySummaryRequestId;
  activitySummaryRefreshing = true;
  renderYoagentPanel({preserveDraft: true, scrollBottom: false, summaryOnly: true});
  try {
    const response = await apiFetch(`/api/activity-summary${options.force ? '?force=1' : ''}`, {cache: 'no-store'});
    const payload = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(payload.error || response.status);
    if (!requestIsCurrent()) return;
    activitySummaryPayload = payload;
  } catch (error) {
    if (!requestIsCurrent()) return;
    activitySummaryPayload = {
      ...activitySummaryPayload,
      errors: [String(error)],
      global: {lines: [`activity summary unavailable: ${String(error)}`]},
    };
    if (!options.silent) statusErr(`activity summary failed: ${esc(error)}`);
  } finally {
    if (requestIsCurrent()) {
      activitySummaryRefreshing = false;
      renderInfoPanel();
      renderYoagentPanel({preserveDraft: true, scrollBottom: false, summaryOnly: true});
    }
  }
}

function editorSchemePreferenceChoices(options = {}) {
  const preferredOrder = [
    'dark',
    'vscode-dark-plus',
    'one-dark',
    'dracula',
    'monokai',
    'nord',
    'vscode-light-plus',
    'yolomux-light',
    'github-light',
    'one-light',
    'solarized-light',
  ];
  const ids = [...preferredOrder, ...EDITOR_SCHEME_IDS.filter(id => !preferredOrder.includes(id))];
  return ids
    .filter(id => options.dark === undefined || EDITOR_SCHEMES[id]?.dark === options.dark)
    .map(id => {
      const scheme = EDITOR_SCHEMES[id];
      return {value: id, label: scheme.label, group: scheme.dark ? 'Dark' : 'Light'};
    });
}

